        public static Series getPrice(string priceType, Series op, Series hi, Series lo, Series cl)
        {
            var price = cl;
            if (priceType == "Open") price = op;
            else if (priceType == "High") price = hi;
            else if (priceType == "Low") price = lo;
            return price;
        }

