        private static Dictionary<string, string> createChoices(string[] choices)
        {
            var parmChoices = new Dictionary<string, string>();
            foreach (var choice in choices)
            {
                parmChoices[choice] = choice;
            }
            return parmChoices;
        }

        public static List<string> GetIntervals(string input)
        {
            List<string> intervals = new List<string>();
            string[] conditions = input.Split('\u0001');
            foreach (string condition in conditions)
            {
                if (condition.Length > 0)
                {
                    string[] field = condition.Split('\u0002');
                    string conditionName = field[0];
                    string conditionInterval = (field.Length > 1) ? field[1].Replace(" Min", "") : "Daily";
                    if (conditionInterval.Length == 0) conditionInterval = "Daily";
                    intervals = addInterval(conditionInterval, intervals);

                    if (RequiresMidTermInterval(conditionName))
                    {
                        string midTermInterval = Study.getForecastInterval(conditionInterval, 1);
                        intervals = addInterval(midTermInterval, intervals);
                    }
                 }
            }
            return intervals;
        }

        
