        private static List<string> addInterval(string interval, List<string> input)
        {
            List<string> output = input;
            bool found = false;
            foreach (string interval1 in input)
            {
                if (interval == interval1)
                {
                    found = true;
                    break;
                }
            }
            if (!found)
            {
                output.Add(interval);
            }
            return output;
        }

        public static List<string> GetRequiredReferenceData(string condition)
        {
            List<string> output = new List<string>();

            //if (condition == "Beta > 1") output.Add("EQY_BETA_6M");
            //else if (condition == "Beta < 1") output.Add("EQY_BETA_6M");

            if (RequiresIndexBars(condition))
            {
                output.Add("REL_INDEX");
            }
            else if (condition.Contains("Beta"))
            {
                output.Add("BETA_ADJ_OVERRIDABLE");
            }
            else if (condition.Contains("T Test"))
            {
                output.Add("BETA_T_TEST");
            }
			else if (condition.Contains("30 D Vol"))
			{
				output.Add("VOLATILITY_30D");
			}

			return output;
        }

        private static Series getFundamentalSeries(string ticker, int barCount, List<DateTime> dates, string name, Dictionary<string, object> referenceData)
        {
            Series output = new Series(barCount);
            if (referenceData != null)
            {
                List<string> keys = referenceData.Keys.ToList().Where(k => k.Contains(name)).ToList();
                if (keys.Count > 0)
                {
                    keys.Sort(StringComparer.Ordinal);
                    var k = keys[0];
                    var f = k.Split(':');
                    var hasTicker = f.Length == 3;
                    var first_date = hasTicker ? f[2] : f[1];

                    int count = dates.Count;
                    for (int ii = 0; ii < barCount; ii++)
                    {
                        int index = ii + count - barCount;
                        if (index >= 0 && index < dates.Count)
                        {
                            DateTime date = dates[index];
                            var dateText = date.ToString("yyyy-MM-dd");

                            if (dateText.CompareTo(first_date) >= 0)
                            {
                                string key = (hasTicker ? ticker + ":" : "") + name + ":" + dateText;
                                int idx = keys.BinarySearch(key, StringComparer.Ordinal);
                                if (idx < 0)
                                {
                                    idx = ~idx;
                                }
                                if (idx >= 0 && idx < keys.Count)
                                {
                                    key = keys[idx];
									output[ii] = (double)referenceData[key];
								}
                                else
                                {
                                    output[ii] = output[ii - 1];
                                }
                            }
                            else
                            {
                                output[ii] = double.NaN;
                            }
                        }
                    }
                }
            }
            return output;
        }


        public static Indicator getIndicator(string input)
        {
            Indicator output = null;
            if (input.Length > 0)
            {
                if (input[input.Length - 1] == ')')
                {
                    var fields = input.Replace(")", "").Split('(');
                    if (fields.Length == 2)
                    {
                        output = CreateIndicator(fields[0]);
                        if (fields[1].Length > 0)
                        {
                            var parms = fields[1].Split(';');
                            foreach (var parm in parms)
                            {
                                var items = parm.Split('=');
                                var parmName = items[0];
                                var parmValue = items[1];
                                output.Parameters[parmName].FromString(parmValue);
                            }
                        }
                    }
                }
            }
            return output;
        }

		public static string GetReverseCondition(string name)
		{
			string[] tokens = name.Split(' ');

			string[,] replace = {
				{"Up", "Dn"},
				{">", "<"},
				{">=", "<="},
				{"+", "-"},
				{"Above", "Below"},
				{"Bullish", "Bearish"},
				{"Long", "Short" },
				{"OB", "OS"},
				{"0", "100"},
				{"10", "90"},
				{"20", "80"},
				{"30", "70"},
				{"40", "60"}
			};

			string reverseName = "";

			foreach (string token in tokens)
			{
				string field = token;
				for (int ii = 0; ii < replace.GetLength(0); ii++)
				{
					if (token == replace[ii, 0])
					{
						field = replace[ii, 1];
						break;
					}
					else if (token == replace[ii, 1])
					{
						field = replace[ii, 0];
						break;
					}
				}
				reverseName += (((reverseName.Length > 0) ? " " : "") + field);
			}

			return reverseName;
		}


        public static Series Calculate(string name, string symbol, string[] intervalList, int barCount,
            Dictionary<string, List<DateTime>> times, Dictionary<string, Series[]> bars, Dictionary<string, object> referenceData)
        {
            name = name.Trim();

            string interval = intervalList[0];
            string interval1 = (intervalList.Length > 1) ? intervalList[1] : interval;

            Series series = new Series(barCount, 0);

            var indicator = getIndicator(name);

            if (indicator != null)
            {
                var op = bars[interval][0];
                var hi = bars[interval][0];
                var lo = bars[interval][0];
                var cl = bars[interval][0];

                if (indicator.Name == "ADX")
                {
                    var period = (indicator.Parameters["Period"] as NumberParameter).Value;

                    series = atm.calculateADX(hi, lo, cl, (int)period);
                }
                else if (indicator.Name == "DMI Up")
                {
                    var maType = (indicator.Parameters["MAType"] as ChoiceParameter).Value;
                    var period = (indicator.Parameters["Period"] as NumberParameter).Value;

                    series = atm.calculateDMI(hi, lo, cl, maType, (int)period)[0];
                }
                else if (indicator.Name == "DMI Down")
                {
                    var maType = (indicator.Parameters["MAType"] as ChoiceParameter).Value;
                    var period = (indicator.Parameters["Period"] as NumberParameter).Value;

                    series = atm.calculateDMI(hi, lo, cl, maType, (int)period)[1];
                }
                else if (indicator.Name == "D DIF")
                {
                    var maType = (indicator.Parameters["MAType"] as ChoiceParameter).Value;
                    var period = (indicator.Parameters["Period"] as NumberParameter).Value;

                    series = atm.calculateDDIF(hi, lo, cl, maType, (int)period);
                }
                else if (indicator.Name == "OSC")
                {
                    var type1 = indicator.Parameters["Type1"] as ChoiceParameter;
                    var type2 = indicator.Parameters["Type2"] as ChoiceParameter;
                    var priceType1 = indicator.Parameters["Price1"] as ChoiceParameter;
                    var priceType2 = indicator.Parameters["Price2"] as ChoiceParameter;
                    var period1 = indicator.Parameters["Period1"] as NumberParameter;
                    var period2 = indicator.Parameters["Period2"] as NumberParameter;
                    var colorParm = indicator.Parameters["Color"] as ColorParameter;
                    var curveTypeParm = indicator.Parameters["DisplayType"] as ChoiceParameter;

                    var price1 = Conditions.getPrice(priceType1.Value, op, hi, lo, cl);
                    var price2 = Conditions.getPrice(priceType2.Value, op, hi, lo, cl);

                    Series ma1 = atm.calculateMovingAvg(type1.Value, price1, (int)period1.Value);
                    Series ma2 = atm.calculateMovingAvg(type2.Value, price2, (int)period2.Value);
                    series = ma1 - ma2;

                }
                else if (indicator.Name == "ROC")
                {
                    var priceType = (indicator.Parameters["Price"] as ChoiceParameter).Value;
                    var period = (indicator.Parameters["Period"] as NumberParameter).Value;

                    var price = getPrice(priceType, op, hi, lo, cl);
                    series = atm.calculateROC(price, (int)period);
                }
                //else if (indicator.Name == "TRIX")
                //{
                //var period = (indicator.Parameters["Period"] as NumberParameter).Value;

                // series = atm.calculateTRIX(hi, lo, cl, (int)period);
                //}
                else if (indicator.Name == "ATR")
                {
                    var maType = (indicator.Parameters["MAType"] as ChoiceParameter).Value;
                    var period = (indicator.Parameters["Period"] as NumberParameter).Value;

                    series = atm.calculateATR(hi, lo, cl, maType, (int)period);
                }
                else if (indicator.Name == "MA 1" || indicator.Name == "MA 2" || indicator.Name == "MA 3")
                {
                    var period = (indicator.Parameters["Period"] as NumberParameter).Value;
                    var priceType = (indicator.Parameters["Price"] as ChoiceParameter).Value;
                    var maType = (indicator.Parameters["Type"] as ChoiceParameter).Value;

                    var price = getPrice(priceType, op, hi, lo, cl);

                    series = atm.calculateMovingAvg(maType, price, (int)period);
                }
                else if (indicator.Name == "MOM")
                {
                    var period = (indicator.Parameters["Period"] as NumberParameter).Value;
                    var price = cl;
                    series = atm.calculateMOM(price, (int)period);
                }
