                var scSig = atm.calculateSCSig(score, rp, 2);
                Series pt = atm.calculatePressureAlert(op, hi, lo, cl);
                var up = Series.Equal(scSig, 1) & pt > 0;
                var dn = Series.Equal(scSig, -1) & pt < 0;
