                Series ft = atm.calculateFT(hi, lo, cl);
                Series ftgu = ft.IsRising();
                Series ftgd = ft.IsFalling();
                var up = Series.Equal(scSig, 1) & (Series.Equal(ftgu, 1) & Series.Equal(ftgd.ShiftLeft(1), 1) | Series.Equal(scSig.ShiftLeft(1), -1));
                var dn = Series.Equal(scSig, -1) & (Series.Equal(ftgd, 1) & Series.Equal(ftgu.ShiftLeft(1), 1) | Series.Equal(scSig.ShiftLeft(1), 1));
                series = up - dn;
