                Series cl = bars[interval][3];
                List<Series> tp = atm.calculateFastTurningPoints(hi, lo, cl, atm.calculateFT(hi, lo, cl));
                series = tp[1];

            }
            else if (name == "ST Turning Point Up")
            {
                Series hi = bars[interval][1];
                Series lo = bars[interval][2];
                Series cl = bars[interval][3];
                List<Series> tp = atm.calculateSlowTurningPoints(hi, lo, cl, atm.calculateST(hi, lo, cl));
                series = tp[0];
            }

            else if (name == "ST Turning Point Dn")
            {
                Series hi = bars[interval][1];
                Series lo = bars[interval][2];
                Series cl = bars[interval][3];
                List<Series> tp = atm.calculateSlowTurningPoints(hi, lo, cl, atm.calculateST(hi, lo, cl));
                series = tp[1];
            }

            else if (name == "ATM Trend Strength Bar")
            {
                Series hi = bars[interval][1];
                Series lo = bars[interval][2];
                Series cl = bars[interval][3];
                int upperLimit = 102;
                int lowerLimit = -2;
                Series TSB = atm.calculateTSB(hi, lo, cl);
                series = (((TSB - 30) * ((double)upperLimit - lowerLimit) / (70 - 30)) + lowerLimit).ClipAbove(upperLimit).ClipBelow(lowerLimit);
            }

            else if (name == "ATM Pressure")
            {
                Series hi = bars[interval][1];
                Series lo = bars[interval][2];
                Series cl = bars[interval][3];
                int upperLimit = 102;
                int lowerLimit = -2;
                Series TSB = atm.calculateTSB(hi, lo, cl);
                series = (((TSB - 30) * ((double)upperLimit - lowerLimit) / (70 - 30)) + lowerLimit).ClipAbove(upperLimit).ClipBelow(lowerLimit);

            }

            else if (name == "ATM Trend Line")
            {
                Series hi = bars[interval][1];
                Series lo = bars[interval][2];
                Series cl = bars[interval][3];

                List<Series> tl = atm.calculateTrendLines(hi, lo, cl, 3);
                int count = tl[0].Count;
                Series output = new Series(count);
                for (int jj = 0; jj < count; jj++)
                {
                    if (!double.IsNaN(tl[0][jj]))
                    {
                        output[jj] = 1;
                    }
                    else if (!double.IsNaN(tl[1][jj]))
                    {
                        output[jj] = -1;
                    }
                    else
                    {
                        output[jj] = 0;
                    }
                }
                series = output;
            }
            else if (name.StartsWith("Beta") || name.StartsWith("T Test") || name.StartsWith("30 D Vol"))
            {
                var fields = name.Replace("Beta ", "").Replace("T Test ", "").Replace("30 D Vol ", "").Split(' ');
                var dataName = name.StartsWith("Beta") ? "BETA_ADJ_OVERRIDABLE" : name.StartsWith("30 D Vol") ? "VOLATILITY_30D" : "BETA_T_TEST";
                var relation = fields[0];
                var value = double.Parse(fields[1]);
                Series data = getFundamentalSeries(symbol, barCount, times[interval], dataName, referenceData);

                series = new Series(data.Count, 0);
				if (fields.Length > 2 && fields[2].CompareTo("with") == 0)
                {
					string condName = string.Join(" ", fields.Skip(3));
					var conditionSeries = Calculate(condName, symbol, intervalList, barCount, times, bars, referenceData);
                    for (int i = 0; i < conditionSeries.Count; i++)
                    {
                        var v = conditionSeries[i];
                        var sig = false;
                        var rel = v == 0 ? reverseRelation(relation) : relation;
                        var val = v == 0 ? 2.0 - value : value;
						if (rel == ">=") sig = v >= val;
						else if (rel == ">") sig = v > val;
						else if (rel == "<") sig = v < val;
						else if (rel == "<=") sig = v <= val;
						else if (rel == "=") sig = v == val;
                        series[i] = sig ? 1 : 0;
					};
				}
                else
                {
                    if (relation == ">=") series = Series.GreaterEqual(data, value);
                    else if (relation == ">") series = Series.Greater(data, value);
                    else if (relation == "<") series = Series.Less(data, value);
                    else if (relation == "<=") series = Series.LessEqual(data, value);
                    else if (relation == "=") series = Series.Equal(data, value);
                }
            }

            // todo add price conditions
            else
            {
                string[] fields = name.Split('\u0004');
                if (fields.Length == 1)
                {
                    string dataName = Conditions.GetFieldNameFromDescription(fields[0].Trim());
                    series = getFundamentalSeries(symbol, barCount, times[interval], dataName, referenceData);
                }
                if (fields.Length == 3)
                {
                    string dataName = Conditions.GetFieldNameFromDescription(fields[0].Trim());
                    string relation = fields[1].Trim();
                    double value = 0;
                    if (double.TryParse(fields[2].Trim(), out value))
                    {
                        Series data = getFundamentalSeries(symbol, barCount, times[interval], dataName, referenceData);



                        if (relation == ">=") series = Series.GreaterEqual(data, value);
                        else if (relation == ">") series = Series.Greater(data, value);
                        else if (relation == "<") series = Series.Less(data, value);
                        else if (relation == "<=") series = Series.LessEqual(data, value);
                        else if (relation == "=") series = Series.Equal(data, value);
                    }
                }
            }

            return series;
        }

        private static string reverseRelation(string input)
        {
            if (input == ">") return "<";
            else if (input == "<") return ">";
            else if (input == ">=") return "<=";
            else if (input == "<=") return ">=";
            else return input;
		}

        private static Series calculateVoltility(int period, Series[] bars)
        {
            int size = 20;
            Series output = new Series(size, double.NaN);
            Series cl = bars[3];
            double annualizingFactor = Math.Sqrt(252);
            for (int ii = 0; ii < size; ii++)
            {
                int ago = size - 1 - ii;
                int index = cl.Count - 1 - ago;
                double volatility = atm.GetVolatility(period, index, cl);
                output[ii] = volatility / annualizingFactor;
            }
            return output;
        }

