        private static Series calculateUpBar(Series[] bars)
        {
            Dictionary<string, Series> signals = new Dictionary<string, Series>();
            Series op = bars[0];
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            Series cl1 = cl.ShiftRight(1);
            Series hi1 = hi.ShiftRight(1);
            Series lo1 = lo.ShiftRight(1);
            Series up = (op < cl) & (cl > cl1) & (cl1 > (lo1 + (hi1 - lo1) * .50));
            Series barUp = up;

            return barUp;
        }

