        private static Series calculateAllXSigs(Series[] bars)
        {
            Dictionary<string, Series> signals = new Dictionary<string, Series>();
            Series op = bars[0];
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            signals["X Alert"] = atm.calculateXAlert(hi, lo, cl);
            signals["First Alert"] = atm.calculateFirstAlert(hi, lo, cl, atm.FirstAlertLevelSelection.AllLevels);
            signals["Add On Alert"] = atm.calculateAddOnAlert(hi, lo, cl, atm.AddonAlertLevelSelection.AllLevels);
            signals["Pull Back Alert"] = atm.calculatePullbackAlert(hi, lo, cl);
            signals["Exhaustion Alert"] = atm.calculateExhaustion(hi, lo, cl, atm.ExhaustionLevelSelection.AllLevels);
            signals["Divergence Alert"] = atm.calculateZAlert(hi, lo, cl);
            signals["Pressure Alert"] = atm.calculatePressureAlert(op, hi, lo, cl);
            //signals["PT Alert"] = atm.calculatePTAlert(op, hi, lo, cl);
            //signals["Two Bar Trend"] = atm.calculate2BTAlert(op, hi, lo, cl);
            signals["Two Bar Alert"] = atm.calculateTwoBarPattern(op, hi, lo, cl);

            Series XFAAOAPBExhDivSig = (signals["X Alert"] + signals["First Alert"] + signals["Add On Alert"] + signals["Pull Back Alert"] + signals["Exhaustion Alert"] + signals["Pressure Alert"] + signals["Two Bar Alert"] + signals["Divergence Alert"]).ClipAbove(1).ClipBelow(-1);
            //Series XFAAOAPBExhDivSig = (signals["X Alert"] + signals["First Alert"] + signals["Add On Alert"] + signals["Pull Back Alert"] + signals["Exhaustion Alert"] + signals["Pressure Alert"] + signals["PT Alert"] + signals["Two Bar Alert"] + signals["Two Bar Trend"] + signals["Divergence Alert"]).ClipAbove(1).ClipBelow(-1);
            return (XFAAOAPBExhDivSig);
        }

        private static Series calculateORXSigs(Series[] bars)
        {
            Dictionary<string, Series> signals = new Dictionary<string, Series>();
