        private static Series calculateStandardDeviation(Series[] bars, int period)
        {
            Series cl = bars[3];
            Series stdDev = cl.StdDev(period);
            return stdDev;
        }

        private static Series calculateZScore(Series[] bars, int period1, int period2)
        {
            Series cl = bars[3];
            Series ma1 = cl.SimpleMovingAverage(period1);
            Series ma2 = cl.SimpleMovingAverage(period2);
            Series stdDev = cl.StdDev(period2);
            Series zScore = (ma1 - ma2) / stdDev;
            return zScore;
        }

