        private static Series calculateftOSorftGoingUp(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            Series ft = atm.calculateFT(hi, lo, cl);

            Series ftGoingUp = atm.goingUp(ft);

            Series ftisOS = ft < 10;

            Series FTOSorFTGoingUp = (ftisOS).Or(ftGoingUp);

            return FTOSorFTGoingUp;
        }

        private static Series calculateftOSorstGoingUp(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
