            Series st = atm.calculateST(hi, lo, cl);

            Series stGoingUp = atm.goingUp(st);

            Series ftisOS = ft < 10;

            Series fTOSorSTGoingUp = (ftisOS).Or(stGoingUp);

            return fTOSorSTGoingUp;
        }

