        private static Series calculateFTTurnsUpDn(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftBuy = atm.turnsUpBelowLevel(ft, 100);
            Series ftSell = atm.turnsDnAboveLevel(ft, 0);
            Series ftTurnsUpDn = ftBuy - ftSell;
            return ftTurnsUpDn;
        }

        private static Series calculateFTTurnsDnUp(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftSell = atm.turnsUpBelowLevel(ft, 100);
            Series ftBuy = atm.turnsDnAboveLevel(ft, 0);
            Series ftTurnsDnUp = ftSell - ftBuy;
            return ftTurnsDnUp;
        }

