        private static Series calculatestCrosses30Turns30(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            Series st = atm.calculateST(hi, lo, cl);

            Series st30 = st.CrossesAbove(30);

            Series stRising30 = st.IsRising() & st >= 30;

            Series stCrosses30Turns30 = (st30) & (stRising30);

            return stCrosses30Turns30;
        }

        private static Series calculatestCrosses70Turns70(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            Series st = atm.calculateST(hi, lo, cl);

            Series st70 = st.CrossesBelow(70);

            Series stFalling70 = st.IsFalling() & st <= 70;

            Series stCrosses70Turns70 = (st70) & (stFalling70);

            return stCrosses70Turns70;
        }

