        private static Series calulateftORstTurnsDnOrAllXSigs(Series[] bars)
        {

            Dictionary<string, Series> signals = new Dictionary<string, Series>();

            Series op = bars[0];
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            signals["X Alert"] = atm.calculateXAlert(hi, lo, cl);
            signals["First Alert"] = atm.calculateFirstAlert(hi, lo, cl, atm.FirstAlertLevelSelection.AllLevels);
            signals["Add On Alert"] = atm.calculateAddOnAlert(hi, lo, cl, atm.AddonAlertLevelSelection.AllLevels);
            signals["Pull Back Alert"] = atm.calculatePullbackAlert(hi, lo, cl);
            //signals["Exhaustion Alert"] = atm.calculateExhaustion(hi, lo, cl, atm.ExhaustionLevelSelection.AllLevels);
            //signals["Divergence Alert"] = atm.calculateZAlert(hi, lo, cl);
            signals["Pressure Alert"] = atm.calculatePressureAlert(op, hi, lo, cl);
            signals["Two Bar Alert"] = atm.calculateTwoBarPattern(op, hi, lo, cl);

            Series XFAAOAPBSigDn = (signals["X Alert"] + signals["First Alert"] + signals["Add On Alert"] + signals["Pull Back Alert"] /*+ signals["Exhaustion Alert"] + signals["Pressure Alert"]*/ + signals["Two Bar Alert"] /*+ signals["Divergence Alert"]*/).ClipAbove(1).ClipBelow(-1);
            XFAAOAPBSigDn = XFAAOAPBSigDn.Replace(1, 0).Replace(-1, 1);

            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftDn1 = atm.turnsDnAboveLevel(ft, 0);

            Series st = atm.calculateST(hi, lo, cl);
            Series stDn1 = atm.turnsDnAboveLevel(st, 0);

            Series ftOrstTurnsDn = ftDn1.Or(stDn1);

            Series ftOrstOrXTurnsDn = ftOrstTurnsDn.Or(XFAAOAPBSigDn);

            return ftOrstOrXTurnsDn;
        }

        private static Series calulateftORstTurnsUpOrAllXSigs(Series[] bars)
        {

            Dictionary<string, Series> signals = new Dictionary<string, Series>();

            Series op = bars[0];
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            signals["Entry X Alert"] = atm.calculateEntryXAlerts(hi, lo, cl, atm.FirstAlertLevelSelection.AllLevels, atm.AddonAlertLevelSelection.AllLevels);
            signals["Pressure Alert"] = atm.calculatePressureAlert(op, hi, lo, cl);
            signals["Two Bar Alert"] = atm.calculateTwoBarPattern(op, hi, lo, cl);

            Series XFAAOAPBSigUp = (signals["Entry X Alert"] + signals["Pressure Alert"] + signals["Two Bar Alert"]).ClipAbove(1).ClipBelow(-1);
            XFAAOAPBSigUp = XFAAOAPBSigUp.Replace(-1, 0);

            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftUp1 = atm.turnsUpBelowLevel(ft, 100);

            Series st = atm.calculateST(hi, lo, cl);
            Series stUp1 = atm.turnsUpBelowLevel(st, 100);

            Series ftOrstTurnsUp = ftUp1.Or(stUp1);

            Series ftOrstOrXTurnsUp = ftOrstTurnsUp.Or(XFAAOAPBSigUp);

            return ftOrstOrXTurnsUp;
        }

        private static Series calculateftOrstOrptTurnsUp(Series[] bars)
        {
            Dictionary<string, Series> signals = new Dictionary<string, Series>();
            Series op = bars[0];
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftUp1 = atm.turnsUpBelowLevel(ft, 100);

            Series st = atm.calculateST(hi, lo, cl);
            Series stUp1 = atm.turnsUpBelowLevel(st, 100);

            signals["Pressure Alert"] = atm.calculatePressureAlert(op, hi, lo, cl);
            Series PrsSig3 = signals["Pressure Alert"];

            Series ftOrstORptTurnsUp = ftUp1.Or(stUp1).Or(Series.Equal(PrsSig3, 1));

            return (ftOrstORptTurnsUp);
        }

