        private static Series calculateSTConfirmUp(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftUp1 = atm.turnsUpBelowLevel(ft, 100);
            Series st = atm.calculateST(hi, lo, cl);
            Series stUp1 = atm.turnsUpBelowLevel(st, 100);
            Series stConfUp1 = stUp1.And(ftUp1.Or(ftUp1.ShiftRight(1)).Or(ftUp1.ShiftRight(2)));
            Series stConfUp2 = ftUp1.And(stUp1.Or(stUp1.ShiftRight(1)));
            Series stConfUp = stConfUp1.Or(stConfUp2);

            return stConfUp;
        }

