        private static Series calculatesttsbBullish(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            Series st = atm.calculateST(hi, lo, cl);
            Series stAbove25not75 = (st > 25).And(st < 75);
            Series stGoingUp = atm.goingUp(st);
            Series stStrong = st > 75;
            Series stBullish = ((stAbove25not75).And(stGoingUp)).Or(stStrong);

            //Bullish TSB
            Series ST = atm.calculateST(hi, lo, cl);
            Series EZI = atm.calculateEZI(cl);
            Series TSB = atm.calculateTSB(hi, lo, cl);

            Series upSet = (TSB > 30).And(ST > 75).And((ST.ShiftRight(6) < 20).Or(ST.ShiftRight(7) < 20));
            Series dnSet = (TSB < 70).And(ST < 25).And((ST.ShiftRight(6) > 80).Or(ST.ShiftRight(7) > 80));
            Series upRes = ST < 65;
            Series dnRes = ST > 35;

            Series Utsb = (EZI >= 80).And(TSB >= 70);
            Series Dtsb = (EZI <= 20).And(TSB <= 30);
            Series Uezi = (EZI <= 80).And(TSB >= 70);
            Series Dezi = (EZI >= 20).And(TSB <= 30);
            Series Uset = (TSB < 70) * atm.setReset(upSet, upRes);
            Series Dset = (TSB > 30) * atm.setReset(dnSet, dnRes);

            Series tsbUp = Utsb.Or(Uezi.Or(Uset));

            Series sttsbUp = (stBullish).Or (tsbUp);

            return sttsbUp;
        }

        private static Series calculatesttsbBearish(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            Series st = atm.calculateST(hi, lo, cl);
            Series stBelow75not25 = (st < 75).And(st > 25);
            Series stGoingDn = atm.goingDn(st);
            Series stWeak = st < 25;
            Series stBearish = ((stBelow75not25).And(stGoingDn)).Or(stWeak);

            //Bearsih TSB
            Series ST = atm.calculateST(hi, lo, cl);
            Series EZI = atm.calculateEZI(cl);
            Series TSB = atm.calculateTSB(hi, lo, cl);

            Series upSet = (TSB > 30).And(ST > 75).And((ST.ShiftRight(6) < 20).Or(ST.ShiftRight(7) < 20));
            Series dnSet = (TSB < 70).And(ST < 25).And((ST.ShiftRight(6) > 80).Or(ST.ShiftRight(7) > 80));
            Series upRes = ST < 65;
            Series dnRes = ST > 35;

            Series Utsb = (EZI >= 80).And(TSB >= 70);
            Series Dtsb = (EZI <= 20).And(TSB <= 30);
            Series Uezi = (EZI <= 80).And(TSB >= 70);
            Series Dezi = (EZI >= 20).And(TSB <= 30);
            Series Uset = (TSB < 70) * atm.setReset(upSet, upRes);
            Series Dset = (TSB > 30) * atm.setReset(dnSet, dnRes);

            Series tsbDn = Dezi.Or(Dtsb).Or(Dset);

            Series sttsbDn = (stBearish).Or (tsbDn);

            return sttsbDn;
        }

