        private static Series calculateATMup(Series[] bars)
        {
            Dictionary<string, Series> signals = new Dictionary<string, Series>();
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            Series FT = atm.calculateFT(hi, lo, cl);
            Series ST = atm.calculateST(hi, lo, cl);
            Series EZI = atm.calculateEZI(cl);
            Series TSB = atm.calculateTSB(hi, lo, cl);

            Series upSet = (TSB > 30).And(ST > 75).And((ST.ShiftRight(6) < 20).Or(ST.ShiftRight(7) < 20));
            Series dnSet = (TSB < 70).And(ST < 25).And((ST.ShiftRight(6) > 80).Or(ST.ShiftRight(7) > 80));
            Series upRes = ST < 65;
            Series dnRes = ST > 35;

            Series Utsb = (EZI >= 80).And(TSB >= 70);
            Series Dtsb = (EZI <= 20).And(TSB <= 30);
            Series Uezi = (EZI <= 80).And(TSB >= 70);
            Series Dezi = (EZI >= 20).And(TSB <= 30);
            Series Uset = (TSB < 70) * atm.setReset(upSet, upRes);
            Series Dset = (TSB > 30) * atm.setReset(dnSet, dnRes);

            Series tsbDn = Dezi.Or(Dtsb).Or(Dset);
            Series notBearishTSB = Series.NotEqual(tsbDn, 1);

            //TSB NOT Bearish & FT turns up < 30
            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftGoingUp = atm.goingUp(ft);
            Series ftTurnsUp = atm.turnsUpBelowLevel(ft, 100);
            Series ftless30 = ft < 30;
            Series ft30Turnsup = (ftless30).And(ftTurnsUp).And(notBearishTSB);

            //TSB NOT Bearish & FT and ST Turns Up within 1 bar of each other
            Series st = atm.calculateST(hi, lo, cl);
            Series stGoingUp = atm.goingUp(st);
            Series stless60 = st < 60;
            Series stTurnsUp = atm.turnsUpBelowLevel(st, 100);
            Series ftstTurnUp = (((ftless30).And(ftTurnsUp).And(stGoingUp)).Or((ftGoingUp).And(stTurnsUp).And(stless60)).And(notBearishTSB));

            //X,FA,AOA, PB Buy
            //Series x = atm.calculateXAlert(hi, lo, cl);
            //Series xup = x.Replace(-1,0);
            //Series fa = atm.calculateFirstAlert(hi, lo, cl, atm.FirstAlertLevelSelection.AllLevels);
            //Series faup = x.Replace(-1,0);
            //Series aoa = atm.calculateAddOnAlert(hi, lo, cl, atm.AddonAlertLevelSelection.AllLevels);
            //Series aoaup = x.Replace(-1,0);
            //Series pb = atm.calculatePullbackAlert(hi, lo, cl);
            //Series pbup = x.Replace(-1,0);
            //Series XFAAOAXSig = (xup).Or(faup).Or(aoaup).Or(pbup);

            //ST out of OS
            Series stUp1 = (ST.ShiftRight(1) < 25).And(ST > 25);
            Series stoutOS = stUp1;

            Series ATMup = (ft30Turnsup).Or(ftstTurnUp).Or(stoutOS);

            return ATMup;
        }

        private static Series calculateATMdn(Series[] bars)
        {
            Dictionary<string, Series> signals = new Dictionary<string, Series>();
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            Series FT = atm.calculateFT(hi, lo, cl);
            Series ST = atm.calculateST(hi, lo, cl);
            Series EZI = atm.calculateEZI(cl);
            Series TSB = atm.calculateTSB(hi, lo, cl);

            Series upSet = (TSB > 30).And(ST > 75).And((ST.ShiftRight(6) < 20).Or(ST.ShiftRight(7) < 20));
            Series dnSet = (TSB < 70).And(ST < 25).And((ST.ShiftRight(6) > 80).Or(ST.ShiftRight(7) > 80));
            Series upRes = ST < 65;
            Series dnRes = ST > 35;

            Series Utsb = (EZI >= 80).And(TSB >= 70);
            Series Dtsb = (EZI <= 20).And(TSB <= 30);
            Series Uezi = (EZI <= 80).And(TSB >= 70);
            Series Dezi = (EZI >= 20).And(TSB <= 30);
            Series Uset = (TSB < 70) * atm.setReset(upSet, upRes);
            Series Dset = (TSB > 30) * atm.setReset(dnSet, dnRes);

            Series tsbUp = Utsb.Or(Uezi.Or(Uset));
            Series notBullTSB = Series.NotEqual(tsbUp, 1);

            //FT turns dn > 70
            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftTurnsDn = atm.turnsDnAboveLevel(ft, 0);
            Series ftGoingDn = atm.goingDn(ft);
            Series ftgreater70 = ft > 70;
            Series ft70Turnsdn = (ftgreater70).And(ftTurnsDn).And(notBullTSB);


            //FT and ST Turns Dn
            Series st = atm.calculateST(hi, lo, cl);
            Series stTurnsDn = atm.turnsDnBelowLevel(st, 0);
            Series stGoingDn = atm.goingDn(st);
            Series stgreater40 = st > 40;
            //Series ftstTurnDn = (ftTurnsDn).And(stTurnsDn);
            Series ftstTurnDn = (((ftgreater70).And(ftTurnsDn).And(stGoingDn)).Or((ftGoingDn).And(stTurnsDn).And(stgreater40)).And(notBullTSB));

            //X,FA,AOA,PB Dn
            //Series x = atm.calculateXAlert(hi, lo, cl);
            //Series xdn = x.Replace(1,0).Replace(-1,1);
            //Series fa = atm.calculateFirstAlert(hi, lo, cl, atm.FirstAlertLevelSelection.AllLevels);
            //Series fadn = x.Replace(1,0).Replace(-1,1);
            //Series aoa = atm.calculateAddOnAlert(hi, lo, cl, atm.AddonAlertLevelSelection.AllLevels);
            //Series aoadn = x.Replace(1,0).Replace(-1,1);
            //Series pb = atm.calculatePullbackAlert(hi, lo, cl);
            //Series pbdn = x.Replace(1,0).Replace(-1,1);
            //Series XFAAOAXSig = (xdn).Or(fadn).Or(aoadn).Or(pbdn);

            //ST out of OB

            Series stDn1 = (st.ShiftRight(1) > 75).And(st < 75);
            Series stoutOB = stDn1;

            Series ATMdn = (ft70Turnsdn).Or(ftstTurnDn).Or(stoutOB);

            return ATMdn;
        }

        private static Series calculateisBullish(Series[] bars)
        {
            //Bullish TSB
            Series hi = bars[1];
            Series lo = bars[2];
