        // PR230 Relative 5 Days Eqty/Index .  Change our calculation to get reference Data from BBG  PR240

        public static Series calculateRelativePositionPrice(Dictionary<string, List<DateTime>> times, Dictionary<string, Series[]> bars, string[] intervalList, Dictionary<string, object> referenceData, int ago)
        {
            string interval = intervalList[0];

            Series cl = bars[interval][3];

            int Count = cl.Count;

            Series relPrice = new Series(Count, 0);  // was 50

            if (referenceData != null)
            {
                string key = "Index Prices : " + interval;
                if (referenceData.ContainsKey(key))
                {
                    Series pr = calculatePositionRatio1(times, bars, intervalList, referenceData, ago);

                    Series ic = (Series)referenceData[key];

                    bool inLong = false;
                    bool inShort = false;
                    int enterIndex = 0;

                    for (int ii = 1; ii < pr.Count; ii++)
                    {
                        if (inLong || inShort)
                        {
                            double sym5 = cl[enterIndex];
                            double idx5 = ic[enterIndex];
                            double eret = ((cl[ii] - sym5) / sym5) + 1;
                            double iret = ((ic[ii] - idx5) / idx5) + 1;
                            relPrice[ii] = ((eret / iret) - 1) * 100;
                        }

                        double pr1 = pr[ii - 1];
                        double pr0 = pr[ii];

                        bool enterLong = pr0 == 1.5 && pr1 != 1.5;
                        bool enterShort = pr0 == -1.5 && pr1 != -1.5;
                        bool exitLong = pr0 != 1.5 && pr1 == 1.5;
                        bool exitShort = pr0 != -1.5 && pr1 == -1.5;

                        enterIndex = (enterLong || enterShort) ? ii : enterIndex;

                        inLong = enterLong ? true : exitLong ? false : inLong;
                        inShort = enterShort ? true : exitShort ? false : inShort;
                    }
                }
            }

             return relPrice;
        }

        //FT Sig
        public static Series calculateFTSig(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            int count = cl.Count;

            Series FTSig = new Series(count, 0);

            Series FT = atm.calculateFT(hi, lo, cl);

            Series FtGoingUp = atm.goingUp(FT);
            Series FtGoingDn = atm.goingDn(FT);

            Series FtTurnsUp = atm.turnsUpAboveLevel(FT,0);
            Series FtTurnsDn = atm.turnsDnBelowLevel(FT, 100);

            double ft1 = 0;

            bool inLong = false;
            bool inShort = false;

            double entryPrice = double.NaN;
            for (int ii = 0; ii < count; ii++)
            {
                bool enterLong = !inLong
                                  && (FtTurnsUp[ii] == 1 && FtGoingUp[ii] == 1);

                bool enterShort = !inShort
                                  && (FtTurnsDn[ii] == 1 && FtGoingDn[ii] == 1);

                bool exitLong = inLong
                                  && (FtTurnsDn[ii] == 1);

                bool exitShort = inShort
                                  && (FtTurnsUp[ii] == 1);

                if ((!inLong && enterLong) || (!inShort && enterShort))
                {
                    entryPrice = cl[ii];
                }

                inLong = enterLong ? true : exitLong ? false : inLong;
                inShort = enterShort ? true : exitShort ? false : inShort;

                if (inLong) FTSig[ii] = 1;
                else if (inShort) FTSig[ii] = -1;
                else FTSig[ii] = ft1;

                ft1 = FTSig[ii];
            }
            return FTSig;
        }

        // TSB Sig
        public static Series calculateTSBSig(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            int count = cl.Count;

            Series TSBSig = new Series(count, 0);

            Series ST = atm.calculateST(hi, lo, cl);
            Series EZI = atm.calculateEZI(cl);
            Series TSB = atm.calculateTSB(hi, lo, cl);

            Series upSet = (TSB > 30).And(ST > 75).And((ST.ShiftRight(6) < 20).Or(ST.ShiftRight(7) < 20));
            Series dnSet = (TSB < 70).And(ST < 25).And((ST.ShiftRight(6) > 80).Or(ST.ShiftRight(7) > 80));
            Series upRes = ST < 65;
            Series dnRes = ST > 35;

            Series Utsb = (EZI >= 80).And(TSB >= 70);
            Series Dtsb = (EZI <= 20).And(TSB <= 30);
            Series Uezi = (EZI <= 80).And(TSB >= 70);
            Series Dezi = (EZI >= 20).And(TSB <= 30);
            Series Uset = (TSB < 70) * atm.setReset(upSet, upRes);
            Series Dset = (TSB > 30) * atm.setReset(dnSet, dnRes);

            Series Pressure = TSB.ClipAbove(70).ClipBelow(30);

            // TSB is Bearish
            Series tsbDn = Dezi.Or(Dtsb).Or(Dset);

            // TSB is NOT Bearish  exit shorts   buy long
            Series notBearishTSB = Series.NotEqual(tsbDn, 1);

            // TSB is Bullish  
            Series tsbUp = Uezi.Or(Utsb).Or(Uset);

            // TSB is NOT Bullish  exit long sell short
            Series notBullTSB = Series.NotEqual(tsbUp, 1);

            // Pressure Going Dn
            Series PressureDn1 = atm.goingDn(Pressure);

            // Pressure Going Up
            Series PressureUp1 = atm.goingUp(Pressure);

            Series endTSBUp = Series.Maximum(Series.Equal(tsbDn - (tsbDn >> 1), -1), 8);
            Series endTSBDn = Series.Maximum(Series.Equal(tsbUp - (tsbUp >> 1), -1), 8);

            // BullishTSBEnds
            Series endBullishTSB = endTSBDn;

            // BearishTSBEnds
            Series endBearishTSB = endTSBUp;

            double tsb1 = 0;

            bool inLong = false;
            bool inShort = false;

            double entryPrice = double.NaN;
            for (int ii = 0; ii < count; ii++)
            {
                bool enterLong = !inLong
                                  && (notBearishTSB[ii] == 1 && PressureUp1[ii] == 1) || (tsbUp[ii] == 1);

                bool enterShort = !inShort
                                  && (notBullTSB[ii] == 1 && PressureDn1[ii] == 1) || (tsbDn[ii] == 1);

                bool exitLong = inLong
                                  && (notBullTSB[ii] == 1 || PressureDn1[ii] == 1 || tsbDn[ii] == 1);

                bool exitShort = inShort
                                  && (notBearishTSB[ii] == 1 || PressureUp1[ii] == 1 || tsbUp[ii] == 1);

                if ((!inLong && enterLong) || (!inShort && enterShort))
                {
                    entryPrice = cl[ii];
                }

                inLong = enterLong ? true : exitLong ? false : inLong;
                inShort = enterShort ? true : exitShort ? false : inShort;

                if (inLong) TSBSig[ii] = 1;
                else if (inShort) TSBSig[ii] = -1;
                else TSBSig[ii] = tsb1;

                tsb1 = TSBSig[ii];
            }
            return TSBSig;
        }


        // Strategy 1
        public static Series calculatePositionRatio1(Dictionary<string, List<DateTime>> times, Dictionary<string, Series[]> bars, string[] intervalList, Dictionary<string, object> referenceData, int ago)
        {
            Series SCORE = atm.getScore(times, bars, intervalList);
            Series midTermFTDir = atm.getMidTermFT(times, bars, intervalList);

            Series RelPx = (referenceData == null) ?  null : atm.calculateRelativePrice(intervalList[0], bars[intervalList[0]], referenceData, ago);

            Series op = bars[intervalList[0]][0];
            Series hi = bars[intervalList[0]][1];
            Series lo = bars[intervalList[0]][2];
            Series cl = bars[intervalList[0]][3];
            Series FT = atm.calculateFT(hi, lo, cl);
            Series ST = atm.calculateST(hi, lo, cl);

            int count1 = SCORE.Count;  

            Series PR = new Series(count1);

            Series pAlert = atm.calculatePressureAlertNoFilter(SCORE, op, hi, lo, cl);

            Series twoBar = atm.calculateTwoBarPattern(op, hi, lo, cl);

            List<Series> fttp = atm.getFTTurningPoints(hi, lo, cl); // fttp[0] = turns up price
            //List<Series> sttp = atm.calculateSlowTurningPoints(hi, lo, cl, ST);

            double pr1 = 0;

            int direction = 0;

            bool inLong = false;
            bool inShort = false;

            int ftDir = 0;
            int stDir = 0;

            // Score Alert
            Series score1 = SCORE.ShiftRight(1);
            Series score2 = SCORE.ShiftRight(2);
            Series SAUp = SCORE - score1 > 25 | SCORE - score2 > 25;

            Series score3 = SCORE.ShiftRight(1);
            Series score4 = SCORE.ShiftRight(2);
            Series SADn = SCORE - score3 < -25 | SCORE - score4 < -25;

            Series FTTurnsUp = atm.turnsUpBelowLevel(FT, 100);
            Series FTTurnsDn = atm.turnsDnAboveLevel(FT, 0);

            Series FTTurnsUp50 = atm.turnsUpBelowLevel(FT, 50);
            Series FTTurnsDn50 = atm.turnsDnAboveLevel(FT, 50);

            Series FTTurnsUp30 = atm.turnsUpBelowLevel(FT, 30);
            Series FTTurnsDn70 = atm.turnsDnAboveLevel(FT, 70);

            Series FTTurnsUp40 = atm.turnsUpBelowLevel(FT, 40);
            Series FTTurnsDn60 = atm.turnsDnAboveLevel(FT, 60);

            Series FTTurnsUp25 = atm.turnsUpBelowLevel(FT, 25);
            Series FTTurnsDn75 = atm.turnsDnAboveLevel(FT, 75);

            Series FTTurnsUp15 = atm.turnsUpBelowLevel(FT, 15);
            Series FTTurnsDn85 = atm.turnsDnAboveLevel(FT, 85);

            Series FTTurnsUp75 = atm.turnsUpBelowLevel(FT, 75);
            Series FTTurnsDn25 = atm.turnsDnAboveLevel(FT, 25);

            Series FTTurnsUp95 = atm.turnsUpBelowLevel(FT, 95);
            Series FTTurnsDn5 = atm.turnsDnAboveLevel(FT, 5);

            Series STTurnsUp = atm.turnsUpBelowLevel(ST, 100);
            Series STTurnsDn = atm.turnsDnAboveLevel(ST, 0);

            Series STTurnsUp75 = atm.turnsUpBelowLevel(ST, 75);
            Series STTurnsDn25 = atm.turnsDnAboveLevel(ST, 25);

            Series STTurnsUp25 = atm.turnsUpBelowLevel(ST, 25);
            Series STTurnsDn75 = atm.turnsDnAboveLevel(ST, 75);

            Series STTurnsUp30 = atm.turnsUpBelowLevel(ST, 30);
            Series STTurnsDn70 = atm.turnsDnAboveLevel(ST, 70);

            Series STTurnsUpAbove30 = atm.turnsUpAboveLevel(ST, 30);
            Series STTurnsDnBelow70 = atm.turnsDnBelowLevel(ST, 70);

            // ST Greater than
            Series stgreaterft30 = (ST - FT) > 30;
            Series stgreaterft20 = (ST - FT) > 20;
            Series stgreaterft10 = (ST - FT) > 10;

            // ST Less than
            Series stlessft30 = (ST - FT) < 30;
            Series stlessft20 = (ST - FT) < 20;
            Series stlessft10 = (ST - FT) < 10;

            double entryPrice = double.NaN;

            double ftTurnsDnScore = 0;
            double ftTurnsUpScore = 100;

            double pAlertBuyScore = 0;
            double pAlertSellScore = 100;


            int ftUpAgo = 100;
            int ftDnAgo = 100;
            int stUpAgo = 100;
            int stDnAgo = 100;

            bool upEnb1 = false;
            bool dnEnb1 = false;

            bool upSig = false;
            bool dnSig = false;

            int tradeDuration = 0;
            int pAlertTradeDuration = 0;
            int ftTurnTradeDuration = 0;

            Series ftGoingUp = FT.IsRising();
            Series ftGoingDn = FT.IsFalling();

            Series midTermFTgoingUp = midTermFTDir > 0;
            Series midTermFTgoingDn = midTermFTDir < 0;

            Series stGoingUp = ST.IsRising();
            Series stGoingDn = ST.IsFalling();

            for (int ii = 0; ii < count1; ii++)
            {
                if (!double.IsNaN(cl[ii])) 
                {
                    bool s50to100 = SCORE[ii] >= 50 && SCORE[ii] <= 100;
                    bool s0to50 = SCORE[ii] > 0 && SCORE[ii] < 50;

                    bool s55to100 = SCORE[ii] > 55 && SCORE[ii] <= 100;
                    bool s75to100 = SCORE[ii] > 75 && SCORE[ii] <= 100;
                    bool s65to75 = SCORE[ii] > 65 && SCORE[ii] <= 75;
                    bool s55to65 = SCORE[ii] > 55 && SCORE[ii] <= 65;
                    bool s54to55 = SCORE[ii] > 54 && SCORE[ii] <= 55;
                    bool s53to54 = SCORE[ii] > 53 && SCORE[ii] <= 54;
                    bool s52to53 = SCORE[ii] > 52 && SCORE[ii] <= 53;
                    bool s51to52 = SCORE[ii] > 51 && SCORE[ii] <= 52;
                    bool s50to51 = SCORE[ii] > 50 && SCORE[ii] <= 51;
                    bool s49to50 = SCORE[ii] > 49 && SCORE[ii] <= 50;
                    bool s48to49 = SCORE[ii] > 48 && SCORE[ii] <= 49;
                    bool s47to48 = SCORE[ii] > 47 && SCORE[ii] <= 48;
                    bool s46to47 = SCORE[ii] > 46 && SCORE[ii] <= 47;
                    bool s45to46 = SCORE[ii] > 45 && SCORE[ii] <= 46;
                    bool s35to45 = SCORE[ii] > 35 && SCORE[ii] <= 45;
                    bool s25to35 = SCORE[ii] > 25 && SCORE[ii] <= 35;
                    bool s0to25 = SCORE[ii] > 0 && SCORE[ii] <= 25;
                    bool s0to45 = SCORE[ii] > 0 && SCORE[ii] <= 45;

                    // Defines an up or dn cl 
                    bool upCl70 = ii >= 1 && (cl[ii] > op[ii]) && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii]) * 0.70)); //Up cl above 70% of range
                    bool dnCl30 = ii >= 1 && (cl[ii] < op[ii]) && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii]) * 0.30));

                    bool upCl30 = ii >= 1 && (cl[ii] > op[ii]) && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii]) * 0.30)); //Up cl above 30% of range
                    bool dnCl70 = ii >= 1 && (cl[ii] < op[ii]) && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii]) * 0.70));

                    bool upCltoOp = ii >= 1 && (cl[ii] > op[ii]);
                    bool dnCltoOp = ii >= 1 && (cl[ii] < op[ii]);

                    bool upCl50 = ii >= 1 && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii]) * 0.5));  // cl greater than 50% of range
                    bool dnCl50 = ii >= 1 && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii]) * 0.5));

                    // ST value is between 30 and 70
                    bool st3070 = ST[ii] > 30 && ST[ii] < 70;

                    bool ftstgreater2050 = ST[ii] > 50 && FT[ii] < 20;
                    bool ftstless8050 = ST[ii] < 50 && FT[ii] > 80;

                    bool ftup = ii >= 2 && FT[ii - 2] > FT[ii - 1] && FT[ii - 1] < FT[ii];  // use in upSig
                    bool ftdn = ii >= 2 && FT[ii - 2] < FT[ii - 1] && FT[ii - 1] > FT[ii];
                    bool stup = ii >= 2 && ST[ii - 2] > ST[ii - 1] && ST[ii - 1] < ST[ii] && st3070;  //use in dnSig
                    bool stdn = ii >= 2 && ST[ii - 2] < ST[ii - 1] && ST[ii - 1] > ST[ii] && st3070;

                    bool ftMidGoingUp1Ago = ii >= 2 && midTermFTgoingUp[ii - 2] < midTermFTgoingUp[ii - 1];
                    bool ftMidGoingDn1Ago = ii >= 2 && midTermFTgoingDn[ii - 2] > midTermFTgoingDn[ii - 1];

                    ftUpAgo = (ftup && SCORE[ii] > 50) ? 0 : ftUpAgo + 1;
                    ftDnAgo = (ftdn && SCORE[ii] < 50) ? 0 : ftDnAgo + 1;
                    stUpAgo = (stup && SCORE[ii] > 50) ? 0 : stUpAgo + 1;
                    stDnAgo = (stdn && SCORE[ii] < 50) ? 0 : stDnAgo + 1;

                    // score at ft turning points
                    if (ftup) ftTurnsUpScore = SCORE[ii];
                    if (ftdn) ftTurnsDnScore = SCORE[ii];

                    //FT turns within 4 bars
                    if (ftup) ftDir = 1;
                    else if (ftdn) ftDir = -1;
                    else if (ftDir > 0) ftDir += 1;
                    else if (ftDir < 0) ftDir -= 1;
                    bool ftUpWithin4 = ftDir >= 1 && ftDir <= 4;
                    bool ftDnWithin4 = ftDir <= -1 && ftDir >= -4;

                    //ST turns within 4 bars
                    if (stup) stDir = 1;
                    else if (stdn) stDir = -1;
                    else if (stDir > 0) stDir += 1;
                    else if (stDir < 0) stDir -= 1;
                    bool stUpWithin4 = stDir >= 1 && stDir <= 4;
                    bool stDnWithin4 = stDir <= -1 && stDir >= -4;

                    //palertup or palertdn uses current bar to entry
                    bool pAlertUp = (pAlert[ii] == 1) && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii])));
                    bool pAlertDn = (pAlert[ii] == -1) && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii])));

                    //palert2 uses next bar to entry if it is > or < previous high/low 
                    bool pAlertUp2 = (ii > 0 && pAlert[ii - 1] == 1) && (hi[ii] > hi[ii - 1]) && (cl[ii] > hi[ii - 1]) && upCl50;
                    bool pAlertDn2 = (ii > 0 && pAlert[ii - 1] == -1) && (lo[ii] < lo[ii - 1]) && (cl[ii] < lo[ii - 1]) && dnCl50;

                    //twobarup or twobardn uses current bar to entry
                    bool twoBarUp = (twoBar[ii] == 1) && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii])));
                    bool twoBarDn = (twoBar[ii] == -1) && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii])));

                    //twobar2 uses next bar to entry if it is > or < previous high/low and cl greater or less than 50
                    bool twoBarUp2 = (ii > 0 && twoBar[ii - 1] == 1) && (hi[ii] > hi[ii - 1]) && upCl50;
                    bool twoBarDn2 = (ii > 0 && twoBar[ii - 1] == -1) && (lo[ii] < lo[ii - 1]) && dnCl50;


                    //NEW ENTRIES
                    bool pAlertBuy = (pAlert[ii] == 1) && stgreaterft20[ii] == 1 && SCORE[ii] > 50;
                    bool pAlertSell = (pAlert[ii] == -1) && stlessft20[ii] == 1 && SCORE[ii] < 50;

                    if (pAlertBuy) pAlertBuyScore = SCORE[ii];
                    if (pAlertSell) pAlertSellScore = SCORE[ii];

                    bool STpAlertUp = (ii > 0 && STTurnsUp[ii] == 1 && pAlert[ii - 1] == 1) && (hi[ii] > hi[ii - 1]) && upCl50;
                    bool STpAlertDn = (ii > 0 && STTurnsDn[ii] == 1 && pAlert[ii - 1] == -1) && (lo[ii] < lo[ii - 1]) && dnCl50;

                    bool STtwoBarUp = (ii > 0 && STTurnsUp[ii] == 1 && twoBar[ii - 1] == 1) && (hi[ii] > hi[ii - 1]) && upCl50;
                    bool STtwoBarDn = (ii > 0 && STTurnsDn[ii] == 1 && twoBar[ii - 1] == -1) && (lo[ii] < lo[ii - 1]) && dnCl50;

                    bool STstarUp = (ii > 0 && STTurnsUp[ii] == 1 && SAUp[ii - 1] == 1) && (hi[ii] > hi[ii - 1]) && upCl50;
                    bool STstarDn = (ii > 0 && STTurnsDn[ii] == 1 && SADn[ii - 1] == -1) && (lo[ii] < lo[ii - 1]) && dnCl50;

                    bool FTSTUpEntry = (ii > 0 && STTurnsUp[ii] == 1 && FTTurnsUp[ii] == 1) && upCl30;
                    bool FTSTDnEntry = (ii > 0 && STTurnsDn[ii] == 1 && FTTurnsDn[ii] == 1) && dnCl70;


                    // NEW EXITS
                    bool FTSTUpExit = (ii > 0 && STTurnsUp[ii] == 1 && FTTurnsUp[ii] == 1 && upCl30);
                    bool FTSTDnExit = (ii > 0 && STTurnsDn[ii] == 1 && FTTurnsDn[ii] == 1 && dnCl70);

                    bool FTUpExit = (ii > 0 && FTTurnsUp[ii] == 1);
                    bool FTDnExit = (ii > 0 && FTTurnsDn[ii] == 1);

                    //bool upSig = direction <= 0 && ftup;            
                    //bool dnSig = direction >= 0 && ftdn;

                    //bool upSig = direction <= 0 && pAlertBuy;            
                    //bool dnSig = direction >= 0 && pAlertSell;

                    bool ftTurnUp = (ftUpAgo == 0);
                    bool ftTurnDn = (ftDnAgo == 0);
                    bool stTurnUp = (stUpAgo == 0);
                    bool stTurnDn = (stDnAgo == 0);

                    bool turnUp = !inLong && (ftTurnUp || stTurnUp);
                    bool turnDn = !inShort && (ftTurnDn || stTurnDn);

                    double ftTurningPointPriceUp = fttp[0][ii];
                    double ftTurningPointPriceDn = fttp[1][ii];
                    bool ftAboutToTurnUp1 = (!double.IsNaN(ftTurningPointPriceUp)) ? 100 * (ftTurningPointPriceUp - cl[ii]) / cl[ii] < 1.00 : false;
                    bool ftAboutToTurnDn1 = (!double.IsNaN(ftTurningPointPriceDn)) ? 100 * (cl[ii] - ftTurningPointPriceDn) / cl[ii] < 1.00 : false;

                    ftTurningPointPriceUp = fttp[0][ii + 1];
                    ftTurningPointPriceDn = fttp[1][ii + 1];
                    bool ftAboutToTurnUp2 = (!double.IsNaN(ftTurningPointPriceUp)) ? 100 * (ftTurningPointPriceUp - cl[ii]) / cl[ii] < 1.00 : false;
                    bool ftAboutToTurnDn2 = (!double.IsNaN(ftTurningPointPriceDn)) ? 100 * (cl[ii] - ftTurningPointPriceDn) / cl[ii] < 1.00 : false;

                    //double stTurningPointPriceUp = sttp[0][ii];
                    //double stTurningPointPriceDn = sttp[1][ii];
                    //bool stAboutToTurnUp = (!double.IsNaN(stTurningPointPriceUp)) ? 100 * (stTurningPointPriceUp - cl[ii]) / cl[ii] < 1.00 : false;
                    //bool stAboutToTurnDn = (!double.IsNaN(stTurningPointPriceDn)) ? 100 * (cl[ii] - stTurningPointPriceDn) / cl[ii] < 1.00 : false;

                    bool aboutToTurnUp = ftAboutToTurnUp1 || ftAboutToTurnUp2;  //ftAboutToTurnUp || stAboutToTurnUp;
                    bool aboutToTurnDn = ftAboutToTurnDn1 || ftAboutToTurnDn2;  //ftAboutToTurnDn || stAboutToTurnDn;

                    bool pAlertSigUp = pAlertBuy && aboutToTurnUp;
                    bool pAlertSigDn = pAlertSell && aboutToTurnDn;

                    upEnb1 = (turnUp || pAlertSigUp) ? true : (dnSig || upSig || (ftUpAgo >= 4 && stUpAgo >= 4)) ? false : upEnb1;   // to add more enteries example (turnUp || pAlertSigUp || STpAlertUp)
                    dnEnb1 = (turnDn || pAlertSigDn) ? true : (upSig || dnSig || (ftDnAgo >= 4 && stDnAgo >= 4)) ? false : dnEnb1;   // (turnDn || pAlertSell)

                    upSig = upCl50 && upEnb1;
                    dnSig = dnCl50 && dnEnb1;


                    //bool bp = false;
                    //DateTime time = (intervalList[0] == "Weekly") ? times["Weekly"][ii] : new DateTime();
                    //if (symbol == "GD UN Equity")
                    //{
                    //    if (time.Year == 2014 && time.Month == 10 && time.Day == 17)
                    //    {
                    //        bp = true;
                    //        atm.calculateFastTurningPoints(hi, lo, cl, FT); // fttp[0] = turns up price
                    //    }
                    //}

                    bool upDir = direction <= 0 && upSig;  //uses Up Cl to filter
                    bool dnDir = direction >= 0 && dnSig;
                    bool noDir = (direction >= 0 && (pAlertDn2 || twoBarDn2 || ((ftDnWithin4 || stDnWithin4) && dnCl50))) || (direction <= 0 && (pAlertUp2 || twoBarUp2 || ((ftUpWithin4 || stUpWithin4) && upCl50)));  //uses next bar to exit if condition is true

                    direction = upDir ? 1 : dnDir ? -1 : noDir ? 0 : direction;

                    bool bullish = direction > 0;
                    bool bearish = direction < 0;

                    bool score50up = s50to100;
                    bool score50dn = s0to50;

                    bool scoreUp = s50to100;
                    bool scoreDn = s0to50;
                    if (RelPx != null)
                    {
                        scoreUp = s55to100 || (s54to55 && RelPx[ii] >= .5) || (s53to54 && RelPx[ii] >= .75) || (s52to53 && RelPx[ii] >= 1) || (s51to52 && RelPx[ii] >= 1.25) || (s50to51 && RelPx[ii] >= 1.5);
                        scoreDn = s0to45 || (s45to46 && RelPx[ii] <= -.5) || (s46to47 && RelPx[ii] <= -.75) || (s47to48 && RelPx[ii] <= -1) || (s48to49 && RelPx[ii] <= -1.25) || (s49to50 && RelPx[ii] <= -1.5);
                    }

                    bool enterLong = !inLong && bullish;
                    bool enterShort = !inShort && bearish;

                    bool ftTurnedUpWithin4 = (ii >= 4 && (ftGoingUp[ii] > 0 || ftGoingUp[ii - 1] > 0 || ftGoingUp[ii - 2] > 0 || ftGoingUp[ii - 3] > 0));
                    bool stTurnedUpWithin4 = (ii >= 4 && (stGoingUp[ii] > 0 || stGoingUp[ii - 1] > 0 || stGoingUp[ii - 2] > 0 || stGoingUp[ii - 3] > 0));
                    bool ftTurnedDnWithin4 = (ii >= 4 && (ftGoingDn[ii] > 0 || ftGoingDn[ii - 1] > 0 || ftGoingDn[ii - 2] > 0 || ftGoingDn[ii - 3] > 0));
                    bool stTurnedDnWithin4 = (ii >= 4 && (stGoingDn[ii] > 0 || stGoingDn[ii - 1] > 0 || stGoingDn[ii - 2] > 0 || stGoingDn[ii - 3] > 0));

                    bool stUpExit = (ii >= 2 && (st3070 && stGoingDn[ii] > 0 && stGoingDn[ii - 1] > 0));
                    bool stDnExit = (ii >= 2 && (st3070 && stGoingUp[ii] > 0 && stGoingUp[ii - 1] > 0));

                    bool ClgreaterCl3 = (ii >= 3 && (cl[ii] > cl[ii - 3]));
                    bool CllessCl3 = (ii >= 3 && (cl[ii] < cl[ii - 3]));

                    tradeDuration = (enterLong || enterShort) ? 0 : tradeDuration + 1;
                    pAlertTradeDuration = (enterLong && !turnUp || enterShort && !turnDn) ? 0 : pAlertTradeDuration + 1;
                    ftTurnTradeDuration = (enterLong && turnUp || enterShort && turnDn) ? 0 : ftTurnTradeDuration + 1;

                    int longStopIndex = ii - pAlertTradeDuration;
                    int shortStopIndex = ii - pAlertTradeDuration;

                    bool longCancel1 = (pAlertTradeDuration == 4 && !(ftTurnedUpWithin4 || stTurnedUpWithin4));
                    bool longCancel2 = (pAlertTradeDuration <= 4 && longStopIndex >= 0 && cl[ii] < 0.99 * lo[longStopIndex]);
                    bool longCancel3 = ftMidGoingDn1Ago && (ii > 0 && SCORE[ii - 1] <= 50 && SCORE[ii] <= 50);
                    bool longCancel4 = (ftTurnTradeDuration == 3 && stUpExit);
                    //bool longCancel5 = (tradeDuration == 3 && CllessCl3);

                    bool shortCancel1 = (pAlertTradeDuration == 4 && !(ftTurnedDnWithin4 || stTurnedDnWithin4));
                    bool shortCancel2 = (pAlertTradeDuration <= 4 && shortStopIndex >= 0 && cl[ii] > 1.01 * hi[shortStopIndex]);
                    bool shortCancel3 = ftMidGoingUp1Ago && (ii > 0 && SCORE[ii - 1] >= 50 && SCORE[ii] >= 50);
                    bool shortCancel4 = (ftTurnTradeDuration == 3 && stDnExit);
                    //bool shortCancel5 = (tradeDuration == 3 && ClgreaterCl3);

                    bool exitLong = inLong && (!bullish || longCancel1 || longCancel2 || longCancel3 || longCancel4);
                    bool exitShort = inShort && (!bearish || shortCancel1 || shortCancel2 || shortCancel3 || shortCancel4);

                    direction = (direction > 0 && exitLong) ? 0 : ((direction < 0 && exitShort) ? 0 : direction);

                    bool stopLong = inLong && (((cl[ii] - entryPrice) / entryPrice) <= -0.05);
                    bool stopShort = inShort && (((cl[ii] - entryPrice) / entryPrice) >= 0.05);

                    //exitLong = exitLong || stopLong;
                    //exitShort = exitShort || stopShort;

                    if ((!inLong && enterLong) || (!inShort && enterShort))
                    {
                        entryPrice = cl[ii];
                    }

                    inLong = enterLong ? true : exitLong ? false : inLong;
                    inShort = enterShort ? true : exitShort ? false : inShort;

                    if (inLong) PR[ii] = 1.5;
                    else if (inShort) PR[ii] = -1.5;  // commented out makes this a long only strategy 
                    else if (scoreUp) PR[ii] = 1.0;  // was else if (s50to100) PR[ii] =  1.0;
                    else if (scoreDn) PR[ii] = -1.0;   // was else if (s0to50) PR[ii] = -1.0;
                    else PR[ii] = pr1;

                    pr1 = PR[ii];
                }
            }
            return PR; 
        }

        // Strategy 2   Strategy 2 used in Mthly only.   Changed to see how ST Strategy works. 
        public static Series calculatePositionRatio2(Dictionary<string, List<DateTime>> times, Dictionary<string, Series[]> bars, string[] intervalList, Dictionary<string, object> referenceData, int ago)
        {
            Series SCORE = atm.getScore(times, bars, intervalList);

            Series RelPx = atm.calculateRelativePrice(intervalList[0], bars[intervalList[0]], referenceData, ago);

            Series op = bars[intervalList[0]][0];
            Series hi = bars[intervalList[0]][1];
            Series lo = bars[intervalList[0]][2];
            Series cl = bars[intervalList[0]][3];

            Series MTop = bars[intervalList[1]][0];
            Series MThi = bars[intervalList[1]][1];
            Series MTlo = bars[intervalList[1]][2];
            Series MTcl = bars[intervalList[1]][3];

            Series ft1 = atm.calculateFT(MThi, MTlo, MTcl);
            Series ftDir1 = ft1.IsRising() - ft1.IsFalling();
            Series MTFTDir = atm.convert(intervalList[0], intervalList[1], times, ftDir1.ShiftRight(1));  // 1 means MT FT going up and -1 means MT FT going dn
            //Series MTFTDir = atm.convert(intervalList[0], intervalList[1], times, ftDir1);  // 1 means MT FT going up and -1 means MT FT going dn

            Series ftOBOS = (ft1 > 85) - (ft1 < 15);
            Series MTFTOBOS = atm.convert(intervalList[0], intervalList[1], times, ftOBOS); // 1 means MT FT overbought and -1 means MT FT oversold

            Series st2 = atm.calculateST(MThi, MTlo, MTcl);
            Series stDir2 = st2.IsRising();
            Series st30st70 = (st2 > 30) - (st2 < 70);
            Series MTST3070 = atm.convert(intervalList[0], intervalList[1], times, st30st70); // 1 means MT FT overbought and -1 means MT FT oversold

            Series st1 = atm.calculateST(MThi, MTlo, MTcl);
            Series stDir1 = st1.IsRising() - st1.IsFalling();
            Series MTSTDir = atm.convert(intervalList[0], intervalList[1], times, stDir1);    // 1 means MT ST going up and -1 means MT ST going dn

            Series FT = atm.calculateFT(hi, lo, cl);
            Series ST = atm.calculateST(hi, lo, cl);
            Series TSB = atm.calculateTSB(hi, lo, cl);

            // MT P Alert
            Series pAlert1 = atm.convert(intervalList[0], intervalList[1], times, atm.calculatePressureAlert(MTop, MThi, MTlo, MTcl).ShiftRight(1));
            Series MTPAlertDir = atm.convert(intervalList[0], intervalList[1], times, pAlert1);

            // MT 2Bar Alert
            Series MTtwoBar1 = atm.convert(intervalList[0], intervalList[1], times, atm.calculateTwoBarPattern(MTop, MThi, MTlo, MTcl).ShiftRight(1));
            Series MTtwoBarDir = atm.convert(intervalList[0], intervalList[1], times, MTtwoBar1);

            Series pAlert = atm.calculatePressureAlert(op, hi, lo, cl);
            Series twoBar = atm.calculateTwoBarPattern(op, hi, lo, cl);

            // Score Alert
            Series score1 = SCORE.ShiftRight(1);
            Series score2 = SCORE.ShiftRight(2);
            Series SAUp = SCORE - score1 > 25 | SCORE - score2 > 25;

            Series score3 = SCORE.ShiftRight(1);
            Series score4 = SCORE.ShiftRight(2);
            Series SADn = SCORE - score3 < -25 | SCORE - score4 < -25;

            // ST Fails to Confirms Dn
            Series ftDn1 = atm.turnsDnAboveLevel(FT, 0);
            Series stDn1 = atm.turnsDnAboveLevel(ST, 0);
            Series stGoingUp = atm.goingUp(ST);
            Series ftdn2ago = ftDn1.ShiftRight(2) & stGoingUp.ShiftRight(2);
            Series ftdn1ago = ftDn1.ShiftRight(2) & stGoingUp.ShiftRight(1);
            Series ftdnNO = ftDn1.ShiftRight(2) & stGoingUp;

            Series ftFailDn = ftdn2ago.And(ftdn1ago.And(ftdnNO));

            // ST Fails to Confirms Up
            Series ftUp1 = atm.turnsUpBelowLevel(FT, 100);
