            Series FTTurnsDn85 = atm.turnsDnAboveLevel(FT, 85);

            Series FTTurnsUp75 = atm.turnsUpBelowLevel(FT, 75);
            Series FTTurnsDn25 = atm.turnsDnAboveLevel(FT, 25);

            Series FTTurnsUp95 = atm.turnsUpBelowLevel(FT, 95);
            Series FTTurnsDn5 = atm.turnsDnAboveLevel(FT, 5);

            Series STTurnsUp = atm.turnsUpBelowLevel(ST, 100);
            Series STTurnsDn = atm.turnsDnAboveLevel(ST, 0);

            Series STTurnsUp75 = atm.turnsUpBelowLevel(ST, 75);
            Series STTurnsDn25 = atm.turnsDnAboveLevel(ST, 25);

            Series STTurnsUp25 = atm.turnsUpBelowLevel(ST, 25);
            Series STTurnsDn75 = atm.turnsDnAboveLevel(ST, 75);

            Series STTurnsUp30 = atm.turnsUpBelowLevel(ST, 30);
            Series STTurnsDn70 = atm.turnsDnAboveLevel(ST, 70);

