                //bool enterShort = !inShort && (MTFTDir[ii] == -1) && (stlessft10[ii] == 1) && FT[ii] > 50 && dn &&
                //    (SADn[ii] == 1 || FTTurnsDn[ii] == 1 || (pAlertDn && stlessft30[ii] == 1) || (twoBarDn && stlessft30[ii] == 1));

                //bool enterShort = !inShort && (MTFTDir[ii] == -1 || (MTFTDir[ii] != -1 && MTFTOBOS[ii] == 1 && FT[ii] > 80 && FTTurnsDn[ii] == 1));  // && FT[ii] > 50 && up && FTTurnsDn[ii] == 1
                //bool exitLong = inLong && (!up) &&
