                bool st3070 = ST[ii] > 30 && ST[ii] < 70;  

                //FT turns within 4 bars
                if (ftup) ftDir = 1;
                else if (ftdn) ftDir = -1;
                else if (ftDir > 0) ftDir += 1;
                else if (ftDir < 0) ftDir -= 1;
                bool ftUpWithin4 = ftDir >= 1 && ftDir <= 4;
                bool ftDnWithin4 = ftDir <= -1 && ftDir >= -4;

                //ST turns within 4 bars
                if (stup) stDir = 1;
                else if (stdn) stDir = -1;
                else if (stDir > 0) stDir += 1;
                else if (stDir < 0) stDir -= 1;
                bool stUpWithin4 = stDir >= 1 && stDir <= 4;
                bool stDnWithin4 = stDir <= -1 && stDir >= -4;

                //CL up within 4 bars
                if (upCl) clDir = 1;
                else if (dnCl) clDir = -1;
                else if (clDir > 0) clDir += 1;
                else if (clDir < 0) clDir -= 1;
                bool clUpWithin4 = clDir >= 1 && clDir <= 4;
                bool clDnWithin4 = clDir <= -1 && clDir >= -4;

                //palertup or palertdn uses current bar to entry
                bool pAlertUp = (pAlert[ii] == 1) && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii])));
                bool pAlertDn = (pAlert[ii] == -1) && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii])));

                //palert2 uses next bar to entry if it is > or < previous high/low 
                bool pAlertUp2 = (ii > 0 && pAlert[ii - 1] == 1) && (hi[ii] > hi[ii - 1]);
                bool pAlertDn2 = (ii > 0 && pAlert[ii - 1] == -1) && (lo[ii] < lo[ii - 1]);

                //twobarup or twobardn uses current bar to entry
                bool twoBarUp = (twoBar[ii] == 1) && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii])));
                bool twoBarDn = (twoBar[ii] == -1) && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii])));

                //twobar2 uses next bar to entry if it is > or < previous high/low 
                bool twoBarUp2 = (ii > 0 && twoBar[ii - 1] == 1) && (hi[ii] > hi[ii - 1]);
                bool twoBarDn2 = (ii > 0 && twoBar[ii - 1] == -1) && (lo[ii] < lo[ii - 1]);

                bool upDir = direction <= 0 && ((upCl && (ftUpWithin4 || stUpWithin4)));  //uses Up Cl to filter
                bool dnDir = direction >= 0 && ((dnCl && (ftDnWithin4 || stDnWithin4)));

                bool noDir = (direction >= 0 && (pAlertDn || twoBarDn)) || (direction <= 0 && (pAlertUp || twoBarUp));  // uses current cl to exit if condition is true
                //bool noDir = (direction >= 0 && (pAlertDn2 || twoBarDn2)) || (direction <= 0 && (pAlertUp2 || twoBarUp2));  //uses next bar to exit if condition is true              
                
                direction = upDir ? 1 : dnDir ? -1 : noDir ? 0 : direction;

                bool up = direction > 0;
                bool dn = direction < 0;

                bool scoreUp = s55to100 || (s54to55 && RelPx[ii] >= .5) || (s53to54 && RelPx[ii] >= .75) || (s52to53 && RelPx[ii] >= 1) || (s51to52 && RelPx[ii] >= 1.25) || (s50to51 && RelPx[ii] >= 1.5);
                bool scoreDn = s0to45 || (s45to46 && RelPx[ii] <= -.5) || (s46to47 && RelPx[ii] <= -.75) || (s47to48 && RelPx[ii] <= -1) || (s48to49 && RelPx[ii] <= -1.25) || (s49to50 && RelPx[ii] <= -1.5);

                //bool enterLong = !inLong && (MTFTDir[ii] == 1) && (stgreaterft10[ii] == 1) && FT[ii] < 50 && up && 
                //    (SAUp[ii] == 1 || FTTurnsUp[ii] == 1 || (pAlertUp && stgreaterft30[ii] == 1) || (twoBarUp && stgreaterft30[ii] == 1));
               
                //bool enterLong = !inLong && (MTFTDir[ii] == 1 || (MTFTDir[ii] != 1 && MTFTOBOS[ii] == -1 && FT[ii] < 20 && FTTurnsUp[ii] == 1)); // &&  FT[ii] < 50 && up && FTTurnsUp[ii] == 1
                //bool enterShort = !inShort && (MTFTDir[ii] == -1) && (stlessft10[ii] == 1) && FT[ii] > 50 && dn &&
                //    (SADn[ii] == 1 || FTTurnsDn[ii] == 1 || (pAlertDn && stlessft30[ii] == 1) || (twoBarDn && stlessft30[ii] == 1));

                //bool enterShort = !inShort && (MTFTDir[ii] == -1 || (MTFTDir[ii] != -1 && MTFTOBOS[ii] == 1 && FT[ii] > 80 && FTTurnsDn[ii] == 1));  // && FT[ii] > 50 && up && FTTurnsDn[ii] == 1
                //bool exitLong = inLong && (!up) &&
                //    (SAUp[ii] == 1 || FTTurnsDn[ii] == 1 || pAlertDn || twoBarDn);
                //bool exitShort = inShort 
                //                 && (!dn) 
                //                 && (SADn[ii] == 1 || FTTurnsUp[ii] == 1 || pAlertUp || twoBarUp);

                //bool enterLong = !inLong && (up && score50up && pAlert[ii] != -1);
                //bool enterShort = !inShort && (dn && score50dn && pAlert[ii] != 1);

                //bool exitLong = inLong && (!up || score50dn);
                //bool exitShort = inShort && (!dn || score50up);


                bool enterLong = !inLong
                                  //&& MTbullish
                                  && (FTTurnsUp[ii] == 1);  //|| (st3070 && STTurnsUp[ii] == 1) || (SAUp[ii] == 1 && FT[ii] < 50) || (pAlertUp && FT[ii] < 20);
                                  //&& (TSB[ii] > 50)
                                  //&& ((MTFTDir[ii] == 1) || (MTPAlertDir[ii] == 1) || (MTtwoBarDir[ii] == 1) || (MTSTDir[ii] == 1 && MTST3070[ii] == 1));
                                  //|| (st3070 && STTurnsUp[ii] == 1) || (SAUp[ii] == 1 && FT[ii] < 50) || (pAlertUp && FT[ii] < 20))); 

                bool enterShort = !inShort
                                  //&& MTbearish
                                  && (FTTurnsDn[ii] == 1); //|| (st3070 && STTurnsDn[ii] == 1) || (SADn[ii] == 1 && FT[ii] > 50) || (pAlertDn && FT[ii] > 80); 
                                  //&& (TSB[ii] < 50)
                                  //&& (FTTurnsDn[ii] == 1 && stlessft30[ii] == 1);
                                  //&& ((MTFTDir[ii] == -1) || (MTPAlertDir[ii] == -1) || (MTtwoBarDir[ii] == -1) || (MTSTDir[ii] == 1 && MTST3070[ii] == 1));
                                  //|| (st3070 && STTurnsDn[ii] == 1) || (SADn[ii] == 1 && FT[ii] > 50) || (pAlertDn && FT[ii] > 80)));   

                bool exitLong = inLong
                                 // && MTbearish
                                  && (FTTurnsDn[ii] == 1);
                                 //&& (TSB[ii] < 50)
                                 //&& (FTTurnsDn[ii] == 1);
                                  //|| (st3070 && STTurnsDn[ii] == 1 && SCORE[ii] < 50) || (SADn[ii] == 1 && FT[ii] > 50 && SCORE[ii] < 50) || (pAlertDn && FT[ii] > 80 && SCORE[ii] < 50)); 

                bool exitShort = inShort
                                  //&& MTbullish
                                  && (FTTurnsUp[ii] == 1);
                                  //&& (TSB[ii] > 50)
                                  //&& (FTTurnsUp[ii] == 1);
                                  //&& ((MTFTDir[ii] == 1) || (MTPAlertDir[ii] == 1) || (MTtwoBarDir[ii] == 1));
                                   //|| (st3070 && STTurnsUp[ii] == 1 && SCORE[ii] > 50) || (SAUp[ii] == 1 && FT[ii] < 50 && SCORE[ii] > 50) || (pAlertUp && FT[ii] < 20 && SCORE[ii] > 50)); 

                bool stopLong   = inLong && (((cl[ii] - entryPrice) / entryPrice) <= -0.10);  // 10% stoploss

                bool stopShort  = inShort && (((cl[ii] - entryPrice) / entryPrice) >= 0.10);  // 10% stoploss

                exitLong = exitLong || stopLong;
                exitShort = exitShort || stopShort;

                if ((!inLong && enterLong) || (!inShort && enterShort))
                {
                    entryPrice = cl[ii];
                }

                inLong = enterLong ? true : exitLong ? false : inLong;
                inShort = enterShort ? true : exitShort ? false : inShort;

                if (inLong) PR[ii] = 1.5;
                else if (inShort) PR[ii] = -1.5;  // commented out makes this a long only strategy 
                // else if (s50to100) PR[ii] = 1.0;
                // else if (s0to50) PR[ii] = -1.0;
                else PR[ii] = pr1;

                pr1 = PR[ii];

            }
            return PR;
        }
        
        
        // Strategy 3   MT in a direction - in and out with STerm   this was Strategy 2.  Moved to Strategy 3 to test simply theory of FT up dn
        public static Series calculatePositionRatio3(Dictionary<string, List<DateTime>> times, Dictionary<string, Series[]> bars, string[] intervalList, Dictionary<string, object> referenceData, int ago)
        {
            Series SCORE = atm.getScore(times, bars, intervalList);

            Series RelPx = atm.calculateRelativePrice(intervalList[0], bars[intervalList[0]], referenceData, ago);

            Series op = bars[intervalList[0]][0];
            Series hi = bars[intervalList[0]][1];
            Series lo = bars[intervalList[0]][2];
            Series cl = bars[intervalList[0]][3];

            Series MTop = bars[intervalList[1]][0];
            Series MThi = bars[intervalList[1]][1];
            Series MTlo = bars[intervalList[1]][2];
            Series MTcl = bars[intervalList[1]][3];

            Series ft1 = atm.calculateFT(MThi, MTlo, MTcl);
            Series ftDir1 = ft1.IsRising() - ft1.IsFalling();
            Series MTFTDir = atm.convert(intervalList[0], intervalList[1], times, ftDir1.ShiftRight(1));  // 1 means MT FT going up and -1 means MT FT going dn
            //Series MTFTDir = atm.convert(intervalList[0], intervalList[1], times, ftDir1);  // 1 means MT FT going up and -1 means MT FT going dn

            Series ftOBOS = (ft1 > 85) - (ft1 < 15);
            Series MTFTOBOS = atm.convert(intervalList[0], intervalList[1], times, ftOBOS); // 1 means MT FT overbought and -1 means MT FT oversold

            Series st2 = atm.calculateST(MThi, MTlo, MTcl);
            Series stDir2 = st2.IsRising();
            Series st30st70 = (st2 > 30) - (st2 < 70);
            Series MTST3070 = atm.convert(intervalList[0], intervalList[1], times, st30st70); // 1 means MT FT overbought and -1 means MT FT oversold

            Series st1 = atm.calculateST(MThi, MTlo, MTcl);
            Series stDir1 = st1.IsRising() - st1.IsFalling();
            Series MTSTDir = atm.convert(intervalList[0], intervalList[1], times, stDir1);    // 1 means MT ST going up and -1 means MT ST going dn

            Series FT = atm.calculateFT(hi, lo, cl);
            Series ST = atm.calculateST(hi, lo, cl);
            Series TSB = atm.calculateTSB(hi, lo, cl);

            // MT P Alert
            Series pAlert1 = atm.convert(intervalList[0], intervalList[1], times, atm.calculatePressureAlert(MTop, MThi, MTlo, MTcl).ShiftRight(1));
            Series MTPAlertDir = atm.convert(intervalList[0], intervalList[1], times, pAlert1);

            // MT 2Bar Alert
            Series MTtwoBar1 = atm.convert(intervalList[0], intervalList[1], times, atm.calculateTwoBarPattern(MTop, MThi, MTlo, MTcl).ShiftRight(1));
            Series MTtwoBarDir = atm.convert(intervalList[0], intervalList[1], times, MTtwoBar1);

            Series pAlert = atm.calculatePressureAlert(op, hi, lo, cl);
            Series twoBar = atm.calculateTwoBarPattern(op, hi, lo, cl);

            // Score Alert
            Series score1 = SCORE.ShiftRight(1);
            Series score2 = SCORE.ShiftRight(2);
            Series SAUp = SCORE - score1 > 25 | SCORE - score2 > 25;

            Series score3 = SCORE.ShiftRight(1);
            Series score4 = SCORE.ShiftRight(2);
            Series SADn = SCORE - score3 < -25 | SCORE - score4 < -25;

            // ST Fails to Confirms Dn
            Series ftDn1 = atm.turnsDnAboveLevel(FT, 0);
            Series stDn1 = atm.turnsDnAboveLevel(ST, 0);
            Series stGoingUp = atm.goingUp(ST);
            Series ftdn2ago = ftDn1.ShiftRight(2) & stGoingUp.ShiftRight(2);
            Series ftdn1ago = ftDn1.ShiftRight(2) & stGoingUp.ShiftRight(1);
            Series ftdnNO = ftDn1.ShiftRight(2) & stGoingUp;

            Series ftFailDn = ftdn2ago.And(ftdn1ago.And(ftdnNO));

            // ST Fails to Confirms Up
            Series ftUp1 = atm.turnsUpBelowLevel(FT, 100);
            Series stUp1 = atm.turnsUpBelowLevel(ST, 100);
            Series stGoingDn = atm.goingDn(ST);
            Series ftup2ago = ftUp1.ShiftRight(2) & stGoingDn.ShiftRight(2);
            Series ftup1ago = ftUp1.ShiftRight(2) & stGoingDn.ShiftRight(1);
            Series ftupNO = ftUp1.ShiftRight(2) & stGoingDn;

            Series ftFailUp = ftup2ago.And(ftup1ago.And(ftupNO));

            // ST Greater than
            Series stgreaterft30 = (ST - FT) > 30;
            Series stgreaterft10 = (ST - FT) > 10;

            // ST Less than
            Series stlessft30 = (ST - FT) < 30;
            Series stlessft10 = (ST - FT) < 10;

            int count1 = SCORE.Count;

            Series PR = new Series(count1);

            double pr1 = 0;

            int direction = 0;

            bool inLong = false;
            bool inShort = false;

            int ftDir = 0;
            int stDir = 0;

            int clDir = 0;


            Series FTTurnsUp = atm.turnsUpBelowLevel(FT, 100);
            Series FTTurnsDn = atm.turnsDnAboveLevel(FT, 0);

            Series FTTurnsUp50 = atm.turnsUpBelowLevel(FT, 50);
            Series FTTurnsDn50 = atm.turnsDnAboveLevel(FT, 50);

            Series FTTurnsUp30 = atm.turnsUpBelowLevel(FT, 30);
            Series FTTurnsDn70 = atm.turnsDnAboveLevel(FT, 70);

            Series FTTurnsUp40 = atm.turnsUpBelowLevel(FT, 40);
            Series FTTurnsDn60 = atm.turnsDnAboveLevel(FT, 60);

            Series FTTurnsUp25 = atm.turnsUpBelowLevel(FT, 25);
            Series FTTurnsDn75 = atm.turnsDnAboveLevel(FT, 75);

            Series FTTurnsUp15 = atm.turnsUpBelowLevel(FT, 15);
            Series FTTurnsDn85 = atm.turnsDnAboveLevel(FT, 85);

            Series FTTurnsUp75 = atm.turnsUpBelowLevel(FT, 75);
            Series FTTurnsDn25 = atm.turnsDnAboveLevel(FT, 25);

            Series FTTurnsUp95 = atm.turnsUpBelowLevel(FT, 95);
            Series FTTurnsDn5 = atm.turnsDnAboveLevel(FT, 5);

            Series STTurnsUp = atm.turnsUpBelowLevel(ST, 100);
            Series STTurnsDn = atm.turnsDnAboveLevel(ST, 0);

            Series STTurnsUp75 = atm.turnsUpBelowLevel(ST, 75);
            Series STTurnsDn25 = atm.turnsDnAboveLevel(ST, 25);

            Series STTurnsUp25 = atm.turnsUpBelowLevel(ST, 25);
            Series STTurnsDn75 = atm.turnsDnAboveLevel(ST, 75);

            Series STTurnsUp30 = atm.turnsUpBelowLevel(ST, 30);
            Series STTurnsDn70 = atm.turnsDnAboveLevel(ST, 70);

            Series STTurnsUpAbove30 = atm.turnsUpAboveLevel(ST, 30);
            Series STTurnsDnBelow70 = atm.turnsDnBelowLevel(ST, 70);

            bool MTbullish = false;
            bool MTbearish = false;

            double entryPrice = double.NaN;
            for (int ii = 0; ii < count1; ii++)
            {
                bool MTFTTurnsDn = ii > 0 && MTFTDir[ii - 1] > 0 && MTFTDir[ii] < 0;
                bool MTFTTurnsUp = ii > 0 && MTFTDir[ii - 1] < 0 && MTFTDir[ii] > 0;
                MTbullish = (MTFTTurnsUp || pAlert1[ii] == 1) ? true : (pAlert1[ii] == -1 || MTFTTurnsDn) ? false : MTbullish;
                MTbearish = (MTFTTurnsDn || pAlert1[ii] == -1) ? true : (pAlert1[ii] == 1 || MTFTTurnsUp) ? false : MTbearish;

                bool s50to100 = SCORE[ii] >= 50 && SCORE[ii] <= 100;
                bool s0to50 = SCORE[ii] > 0 && SCORE[ii] < 50;

                bool s55to100 = SCORE[ii] > 55 && SCORE[ii] <= 100;
                bool s75to100 = SCORE[ii] > 75 && SCORE[ii] <= 100;
                bool s65to75 = SCORE[ii] > 65 && SCORE[ii] <= 75;
                bool s55to65 = SCORE[ii] > 55 && SCORE[ii] <= 65;
                bool s54to55 = SCORE[ii] > 54 && SCORE[ii] <= 55;
                bool s53to54 = SCORE[ii] > 53 && SCORE[ii] <= 54;
                bool s52to53 = SCORE[ii] > 52 && SCORE[ii] <= 53;
                bool s51to52 = SCORE[ii] > 51 && SCORE[ii] <= 52;
                bool s50to51 = SCORE[ii] > 50 && SCORE[ii] <= 51;
                bool s49to50 = SCORE[ii] > 49 && SCORE[ii] <= 50;
                bool s48to49 = SCORE[ii] > 48 && SCORE[ii] <= 49;
                bool s47to48 = SCORE[ii] > 47 && SCORE[ii] <= 48;
                bool s46to47 = SCORE[ii] > 46 && SCORE[ii] <= 47;
                bool s45to46 = SCORE[ii] > 45 && SCORE[ii] <= 46;
                bool s35to45 = SCORE[ii] > 35 && SCORE[ii] <= 45;
                bool s25to35 = SCORE[ii] > 25 && SCORE[ii] <= 35;
                bool s0to25 = SCORE[ii] > 0 && SCORE[ii] <= 25;
                bool s0to45 = SCORE[ii] > 0 && SCORE[ii] <= 45;

                // Defines an up or dn cl 
                bool upCl = (cl[ii] > op[ii]);
                bool dnCl = (cl[ii] < op[ii]);

                // FT and ST up dn
                bool ftup = ii >= 2 && FT[ii - 2] > FT[ii - 1] && FT[ii - 1] < FT[ii];  // use in upSig
                bool ftdn = ii >= 2 && FT[ii - 2] < FT[ii - 1] && FT[ii - 1] > FT[ii];

                bool stup = ii >= 2 && ST[ii - 2] > ST[ii - 1] && ST[ii - 1] < ST[ii];  //use in dnSig
                bool stdn = ii >= 2 && ST[ii - 2] < ST[ii - 1] && ST[ii - 1] > ST[ii];

                // ST value is between 30 and 70
                bool st3070 = ST[ii] > 30 && ST[ii] < 70;

                //FT turns within 4 bars
                if (ftup) ftDir = 1;
                else if (ftdn) ftDir = -1;
                else if (ftDir > 0) ftDir += 1;
                else if (ftDir < 0) ftDir -= 1;
                bool ftUpWithin4 = ftDir >= 1 && ftDir <= 4;
                bool ftDnWithin4 = ftDir <= -1 && ftDir >= -4;

                //ST turns within 4 bars
                if (stup) stDir = 1;
                else if (stdn) stDir = -1;
                else if (stDir > 0) stDir += 1;
                else if (stDir < 0) stDir -= 1;
                bool stUpWithin4 = stDir >= 1 && stDir <= 4;
                bool stDnWithin4 = stDir <= -1 && stDir >= -4;

                //CL up within 4 bars
                if (upCl) clDir = 1;
                else if (dnCl) clDir = -1;
                else if (clDir > 0) clDir += 1;
                else if (clDir < 0) clDir -= 1;
                bool clUpWithin4 = clDir >= 1 && clDir <= 4;
                bool clDnWithin4 = clDir <= -1 && clDir >= -4;

                //palertup or palertdn uses current bar to entry
                bool pAlertUp = (pAlert[ii] == 1) && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii])));
                bool pAlertDn = (pAlert[ii] == -1) && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii])));

                //palert2 uses next bar to entry if it is > or < previous high/low 
                bool pAlertUp2 = (ii > 0 && pAlert[ii - 1] == 1) && (hi[ii] > hi[ii - 1]);
                bool pAlertDn2 = (ii > 0 && pAlert[ii - 1] == -1) && (lo[ii] < lo[ii - 1]);

                //twobarup or twobardn uses current bar to entry
                bool twoBarUp = (twoBar[ii] == 1) && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii])));
                bool twoBarDn = (twoBar[ii] == -1) && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii])));

                //twobar2 uses next bar to entry if it is > or < previous high/low 
                bool twoBarUp2 = (ii > 0 && twoBar[ii - 1] == 1) && (hi[ii] > hi[ii - 1]);
                bool twoBarDn2 = (ii > 0 && twoBar[ii - 1] == -1) && (lo[ii] < lo[ii - 1]);

                bool upDir = direction <= 0 && ((upCl && (ftUpWithin4 || stUpWithin4)));  //uses Up Cl to filter
                bool dnDir = direction >= 0 && ((dnCl && (ftDnWithin4 || stDnWithin4)));

                bool noDir = (direction >= 0 && (pAlertDn || twoBarDn)) || (direction <= 0 && (pAlertUp || twoBarUp));  // uses current cl to exit if condition is true
                //bool noDir = (direction >= 0 && (pAlertDn2 || twoBarDn2)) || (direction <= 0 && (pAlertUp2 || twoBarUp2));  //uses next bar to exit if condition is true              

                direction = upDir ? 1 : dnDir ? -1 : noDir ? 0 : direction;

                bool up = direction > 0;
                bool dn = direction < 0;

                bool scoreUp = s55to100 || (s54to55 && RelPx[ii] >= .5) || (s53to54 && RelPx[ii] >= .75) || (s52to53 && RelPx[ii] >= 1) || (s51to52 && RelPx[ii] >= 1.25) || (s50to51 && RelPx[ii] >= 1.5);
                bool scoreDn = s0to45 || (s45to46 && RelPx[ii] <= -.5) || (s46to47 && RelPx[ii] <= -.75) || (s47to48 && RelPx[ii] <= -1) || (s48to49 && RelPx[ii] <= -1.25) || (s49to50 && RelPx[ii] <= -1.5);

                bool enterLong = !inLong
                                  && MTbullish
                                  && (FTTurnsUp[ii] == 1);  

                bool enterShort = !inShort
                                  && MTbearish
                                  && (FTTurnsDn[ii] == 1); 

                bool exitLong = inLong
                                  && MTbearish
                                  && (FTTurnsDn[ii] == 1);

                bool exitShort = inShort
                                  && MTbullish
                                  && (FTTurnsUp[ii] == 1);
                bool stopLong = inLong && (((cl[ii] - entryPrice) / entryPrice) <= -0.10);  // 10% stoploss

                bool stopShort = inShort && (((cl[ii] - entryPrice) / entryPrice) >= 0.10);  // 10% stoploss

                exitLong = exitLong || stopLong;
                exitShort = exitShort || stopShort;

                if ((!inLong && enterLong) || (!inShort && enterShort))
                {
                    entryPrice = cl[ii];
                }

                inLong = enterLong ? true : exitLong ? false : inLong;
                inShort = enterShort ? true : exitShort ? false : inShort;

                if (inLong) PR[ii] = 1.5;
                else if (inShort) PR[ii] = -1.5;  // commented out makes this a long only strategy 
                else if (s50to100) PR[ii] = 1.0;
                else if (s0to50) PR[ii] = -1.0;
                else PR[ii] = pr1;

                pr1 = PR[ii];

            }
            return PR;
        }

        // Strategy 3   MT in a direction - in and out with STerm   this was Strategy 2.  Moved to Strategy 3 to test simply theory of FT up dn
        public static Series calculatePositionRatio4(Dictionary<string, List<DateTime>> times, Dictionary<string, Series[]> bars, string[] intervalList, Dictionary<string, object> referenceData, int ago)
        {
            Series SCORE = atm.getScore(times, bars, intervalList);

            Series RelPx = atm.calculateRelativePrice(intervalList[0], bars[intervalList[0]], referenceData, ago);

            Series op = bars[intervalList[0]][0];
            Series hi = bars[intervalList[0]][1];
            Series lo = bars[intervalList[0]][2];
            Series cl = bars[intervalList[0]][3];

            Series MTop = bars[intervalList[1]][0];
            Series MThi = bars[intervalList[1]][1];
            Series MTlo = bars[intervalList[1]][2];
            Series MTcl = bars[intervalList[1]][3];

            Series ft1 = atm.calculateFT(MThi, MTlo, MTcl);
            Series ftDir1 = ft1.IsRising() - ft1.IsFalling();
            Series MTFTDir = atm.convert(intervalList[0], intervalList[1], times, ftDir1.ShiftRight(1));  // 1 means MT FT going up and -1 means MT FT going dn
            //Series MTFTDir = atm.convert(intervalList[0], intervalList[1], times, ftDir1);  // 1 means MT FT going up and -1 means MT FT going dn

            Series ftOBOS = (ft1 > 85) - (ft1 < 15);
            Series MTFTOBOS = atm.convert(intervalList[0], intervalList[1], times, ftOBOS); // 1 means MT FT overbought and -1 means MT FT oversold

            Series st2 = atm.calculateST(MThi, MTlo, MTcl);
            Series stDir2 = st2.IsRising();
            Series st30st70 = (st2 > 30) - (st2 < 70);
            Series MTST3070 = atm.convert(intervalList[0], intervalList[1], times, st30st70); // 1 means MT FT overbought and -1 means MT FT oversold

            Series st1 = atm.calculateST(MThi, MTlo, MTcl);
            Series stDir1 = st1.IsRising() - st1.IsFalling();
            Series MTSTDir = atm.convert(intervalList[0], intervalList[1], times, stDir1);    // 1 means MT ST going up and -1 means MT ST going dn

            Series FT = atm.calculateFT(hi, lo, cl);
            Series ST = atm.calculateST(hi, lo, cl);
            Series TSB = atm.calculateTSB(hi, lo, cl);

            // MT P Alert
            Series pAlert1 = atm.convert(intervalList[0], intervalList[1], times, atm.calculatePressureAlert(MTop, MThi, MTlo, MTcl).ShiftRight(1));
            Series MTPAlertDir = atm.convert(intervalList[0], intervalList[1], times, pAlert1);

            // MT 2Bar Alert
            Series MTtwoBar1 = atm.convert(intervalList[0], intervalList[1], times, atm.calculateTwoBarPattern(MTop, MThi, MTlo, MTcl).ShiftRight(1));
            Series MTtwoBarDir = atm.convert(intervalList[0], intervalList[1], times, MTtwoBar1);

            Series pAlert = atm.calculatePressureAlert(op, hi, lo, cl);
            Series twoBar = atm.calculateTwoBarPattern(op, hi, lo, cl);

            // Score Alert
            Series score1 = SCORE.ShiftRight(1);
            Series score2 = SCORE.ShiftRight(2);
            Series SAUp = SCORE - score1 > 25 | SCORE - score2 > 25;

            Series score3 = SCORE.ShiftRight(1);
            Series score4 = SCORE.ShiftRight(2);
            Series SADn = SCORE - score3 < -25 | SCORE - score4 < -25;

            // ST Fails to Confirms Dn
            Series ftDn1 = atm.turnsDnAboveLevel(FT, 0);
            Series stDn1 = atm.turnsDnAboveLevel(ST, 0);
            Series stGoingUp = atm.goingUp(ST);
            Series ftdn2ago = ftDn1.ShiftRight(2) & stGoingUp.ShiftRight(2);
            Series ftdn1ago = ftDn1.ShiftRight(2) & stGoingUp.ShiftRight(1);
            Series ftdnNO = ftDn1.ShiftRight(2) & stGoingUp;

            Series ftFailDn = ftdn2ago.And(ftdn1ago.And(ftdnNO));

            // ST Fails to Confirms Up
            Series ftUp1 = atm.turnsUpBelowLevel(FT, 100);
            Series stUp1 = atm.turnsUpBelowLevel(ST, 100);
            Series stGoingDn = atm.goingDn(ST);
            Series ftup2ago = ftUp1.ShiftRight(2) & stGoingDn.ShiftRight(2);
            Series ftup1ago = ftUp1.ShiftRight(2) & stGoingDn.ShiftRight(1);
            Series ftupNO = ftUp1.ShiftRight(2) & stGoingDn;

            Series ftFailUp = ftup2ago.And(ftup1ago.And(ftupNO));

            // ST Greater than
            Series stgreaterft30 = (ST - FT) > 30;
            Series stgreaterft10 = (ST - FT) > 10;

            // ST Less than
            Series stlessft30 = (ST - FT) < 30;
            Series stlessft10 = (ST - FT) < 10;

            int count1 = SCORE.Count;

            Series PR = new Series(count1);

            double pr1 = 0;

            int direction = 0;

            bool inLong = false;
            bool inShort = false;

            int ftDir = 0;
            int stDir = 0;

            int clDir = 0;


            Series FTTurnsUp = atm.turnsUpBelowLevel(FT, 100);
            Series FTTurnsDn = atm.turnsDnAboveLevel(FT, 0);

            Series FTTurnsUp50 = atm.turnsUpBelowLevel(FT, 50);
            Series FTTurnsDn50 = atm.turnsDnAboveLevel(FT, 50);

            Series FTTurnsUp30 = atm.turnsUpBelowLevel(FT, 30);
            Series FTTurnsDn70 = atm.turnsDnAboveLevel(FT, 70);

            Series FTTurnsUp40 = atm.turnsUpBelowLevel(FT, 40);
            Series FTTurnsDn60 = atm.turnsDnAboveLevel(FT, 60);

            Series FTTurnsUp25 = atm.turnsUpBelowLevel(FT, 25);
            Series FTTurnsDn75 = atm.turnsDnAboveLevel(FT, 75);

            Series FTTurnsUp15 = atm.turnsUpBelowLevel(FT, 15);
            Series FTTurnsDn85 = atm.turnsDnAboveLevel(FT, 85);

            Series FTTurnsUp75 = atm.turnsUpBelowLevel(FT, 75);
            Series FTTurnsDn25 = atm.turnsDnAboveLevel(FT, 25);

            Series FTTurnsUp95 = atm.turnsUpBelowLevel(FT, 95);
            Series FTTurnsDn5 = atm.turnsDnAboveLevel(FT, 5);

            Series STTurnsUp = atm.turnsUpBelowLevel(ST, 100);
            Series STTurnsDn = atm.turnsDnAboveLevel(ST, 0);

            Series STTurnsUp75 = atm.turnsUpBelowLevel(ST, 75);
            Series STTurnsDn25 = atm.turnsDnAboveLevel(ST, 25);

            Series STTurnsUp25 = atm.turnsUpBelowLevel(ST, 25);
            Series STTurnsDn75 = atm.turnsDnAboveLevel(ST, 75);

            Series STTurnsUp30 = atm.turnsUpBelowLevel(ST, 30);
            Series STTurnsDn70 = atm.turnsDnAboveLevel(ST, 70);

            Series STTurnsUpAbove30 = atm.turnsUpAboveLevel(ST, 30);
            Series STTurnsDnBelow70 = atm.turnsDnBelowLevel(ST, 70);

            bool MTbullish = false;
            bool MTbearish = false;

            double entryPrice = double.NaN;
            for (int ii = 0; ii < count1; ii++)
            {
                bool MTFTTurnsDn = ii > 0 && MTFTDir[ii - 1] > 0 && MTFTDir[ii] < 0;
                bool MTFTTurnsUp = ii > 0 && MTFTDir[ii - 1] < 0 && MTFTDir[ii] > 0;
                MTbullish = (MTFTTurnsUp || pAlert1[ii] == 1) ? true : (pAlert1[ii] == -1 || MTFTTurnsDn) ? false : MTbullish;
                MTbearish = (MTFTTurnsDn || pAlert1[ii] == -1) ? true : (pAlert1[ii] == 1 || MTFTTurnsUp) ? false : MTbearish;

                bool s50to100 = SCORE[ii] >= 50 && SCORE[ii] <= 100;
                bool s0to50 = SCORE[ii] > 0 && SCORE[ii] < 50;

                bool s55to100 = SCORE[ii] > 55 && SCORE[ii] <= 100;
                bool s75to100 = SCORE[ii] > 75 && SCORE[ii] <= 100;
                bool s65to75 = SCORE[ii] > 65 && SCORE[ii] <= 75;
                bool s55to65 = SCORE[ii] > 55 && SCORE[ii] <= 65;
                bool s54to55 = SCORE[ii] > 54 && SCORE[ii] <= 55;
                bool s53to54 = SCORE[ii] > 53 && SCORE[ii] <= 54;
                bool s52to53 = SCORE[ii] > 52 && SCORE[ii] <= 53;
                bool s51to52 = SCORE[ii] > 51 && SCORE[ii] <= 52;
                bool s50to51 = SCORE[ii] > 50 && SCORE[ii] <= 51;
                bool s49to50 = SCORE[ii] > 49 && SCORE[ii] <= 50;
                bool s48to49 = SCORE[ii] > 48 && SCORE[ii] <= 49;
                bool s47to48 = SCORE[ii] > 47 && SCORE[ii] <= 48;
                bool s46to47 = SCORE[ii] > 46 && SCORE[ii] <= 47;
                bool s45to46 = SCORE[ii] > 45 && SCORE[ii] <= 46;
                bool s35to45 = SCORE[ii] > 35 && SCORE[ii] <= 45;
                bool s25to35 = SCORE[ii] > 25 && SCORE[ii] <= 35;
                bool s0to25 = SCORE[ii] > 0 && SCORE[ii] <= 25;
                bool s0to45 = SCORE[ii] > 0 && SCORE[ii] <= 45;

                // Defines an up or dn cl 
                bool upCl = (cl[ii] > op[ii]);
                bool dnCl = (cl[ii] < op[ii]);

                // FT and ST up dn
                bool ftup = ii >= 2 && FT[ii - 2] > FT[ii - 1] && FT[ii - 1] < FT[ii];  // use in upSig
                bool ftdn = ii >= 2 && FT[ii - 2] < FT[ii - 1] && FT[ii - 1] > FT[ii];

                bool stup = ii >= 2 && ST[ii - 2] > ST[ii - 1] && ST[ii - 1] < ST[ii];  //use in dnSig
                bool stdn = ii >= 2 && ST[ii - 2] < ST[ii - 1] && ST[ii - 1] > ST[ii];

                // ST value is between 30 and 70
                bool st3070 = ST[ii] > 30 && ST[ii] < 70;

                //FT turns within 4 bars
                if (ftup) ftDir = 1;
                else if (ftdn) ftDir = -1;
                else if (ftDir > 0) ftDir += 1;
                else if (ftDir < 0) ftDir -= 1;
                bool ftUpWithin4 = ftDir >= 1 && ftDir <= 4;
                bool ftDnWithin4 = ftDir <= -1 && ftDir >= -4;

                //ST turns within 4 bars
                if (stup) stDir = 1;
                else if (stdn) stDir = -1;
                else if (stDir > 0) stDir += 1;
                else if (stDir < 0) stDir -= 1;
                bool stUpWithin4 = stDir >= 1 && stDir <= 4;
                bool stDnWithin4 = stDir <= -1 && stDir >= -4;

                //CL up within 4 bars
                if (upCl) clDir = 1;
                else if (dnCl) clDir = -1;
                else if (clDir > 0) clDir += 1;
                else if (clDir < 0) clDir -= 1;
                bool clUpWithin4 = clDir >= 1 && clDir <= 4;
                bool clDnWithin4 = clDir <= -1 && clDir >= -4;

                //palertup or palertdn uses current bar to entry
                bool pAlertUp = (pAlert[ii] == 1) && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii])));
                bool pAlertDn = (pAlert[ii] == -1) && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii])));

                //palert2 uses next bar to entry if it is > or < previous high/low 
                bool pAlertUp2 = (ii > 0 && pAlert[ii - 1] == 1) && (hi[ii] > hi[ii - 1]);
                bool pAlertDn2 = (ii > 0 && pAlert[ii - 1] == -1) && (lo[ii] < lo[ii - 1]);

                //twobarup or twobardn uses current bar to entry
                bool twoBarUp = (twoBar[ii] == 1) && (cl[ii] > (lo[ii] + (hi[ii] - lo[ii])));
                bool twoBarDn = (twoBar[ii] == -1) && (cl[ii] < (lo[ii] + (hi[ii] - lo[ii])));

                //twobar2 uses next bar to entry if it is > or < previous high/low 
                bool twoBarUp2 = (ii > 0 && twoBar[ii - 1] == 1) && (hi[ii] > hi[ii - 1]);
                bool twoBarDn2 = (ii > 0 && twoBar[ii - 1] == -1) && (lo[ii] < lo[ii - 1]);

                bool upDir = direction <= 0 && ((upCl && (ftUpWithin4 || stUpWithin4)));  //uses Up Cl to filter
                bool dnDir = direction >= 0 && ((dnCl && (ftDnWithin4 || stDnWithin4)));

                bool noDir = (direction >= 0 && (pAlertDn || twoBarDn)) || (direction <= 0 && (pAlertUp || twoBarUp));  // uses current cl to exit if condition is true
                //bool noDir = (direction >= 0 && (pAlertDn2 || twoBarDn2)) || (direction <= 0 && (pAlertUp2 || twoBarUp2));  //uses next bar to exit if condition is true              

                direction = upDir ? 1 : dnDir ? -1 : noDir ? 0 : direction;

                bool up = direction > 0;
                bool dn = direction < 0;

                bool scoreUp = s55to100 || (s54to55 && RelPx[ii] >= .5) || (s53to54 && RelPx[ii] >= .75) || (s52to53 && RelPx[ii] >= 1) || (s51to52 && RelPx[ii] >= 1.25) || (s50to51 && RelPx[ii] >= 1.5);
                bool scoreDn = s0to45 || (s45to46 && RelPx[ii] <= -.5) || (s46to47 && RelPx[ii] <= -.75) || (s47to48 && RelPx[ii] <= -1) || (s48to49 && RelPx[ii] <= -1.25) || (s49to50 && RelPx[ii] <= -1.5);


                bool enterLong = !inLong
                                  && scoreUp;


                bool enterShort = !inShort
                                  && scoreDn;


                bool exitLong = inLong
                                  && !scoreUp;


                bool exitShort = inShort
                                  && !scoreDn;
 

                bool stopLong = inLong && (((cl[ii] - entryPrice) / entryPrice) <= -0.10);  // 10% stoploss

                bool stopShort = inShort && (((cl[ii] - entryPrice) / entryPrice) >= 0.10);  // 10% stoploss

                exitLong = exitLong || stopLong;
                exitShort = exitShort || stopShort;

                if ((!inLong && enterLong) || (!inShort && enterShort))
                {
                    entryPrice = cl[ii];
                }

                inLong = enterLong ? true : exitLong ? false : inLong;
                inShort = enterShort ? true : exitShort ? false : inShort;

                if (inLong) PR[ii] = 1.5;
                else if (inShort) PR[ii] = -1.5;  // commented out makes this a long only strategy 
                else if (s50to100) PR[ii] = 1.0;
                else if (s0to50) PR[ii] = -1.0;
                else PR[ii] = pr1;

                pr1 = PR[ii];

            }
            return PR;
        }

        private static Series calculatePREqual(Dictionary<string, List<DateTime>> times, Dictionary<string, Series[]> bars,  string[] intervalList, Dictionary<string, object> referenceData, int ago, double value)
