        }

        private static Series calculateNetSigNetLong(Series op, Series hi, Series lo, Series cl, Series pr, Series rp, Series score, int type)
        {
            Series stSig = atm.calculateSTSig(op, hi, lo, cl, type);
            Series scSig = atm.calculateSCSig(score, rp, type);
            Series prSig = atm.calculatePRSig(pr, type);
            Series output = stSig + scSig + prSig >= 0;
            return output;

        }

