        private static Series calculatescSigUp(Dictionary<string, List<DateTime>> times, Dictionary<string, Series[]> bars, string[] intervalList, Dictionary<string, object> referenceData, int type)
        {
            string interval = intervalList[0];

            Series score = atm.getScore(times, bars, intervalList);
            Series rp = atm.calculateRelativePrice(interval, bars[interval], referenceData, 5);
            Series scSig = atm.calculateSCSig(score, rp, type);

            return Series.Equal(scSig, 1);
        }

