        private static Series calculateSTFT(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            Series ft = atm.calculateFT(hi, lo, cl);

            Series ftUp1 = atm.turnsUpBelowLevel(ft, 100);
            Series ftDn1 = atm.turnsDnAboveLevel(ft, 0);

            Series ftUp2 = atm.turnsUpBelowLevel(ft, 25);
            Series ftDn2 = atm.turnsDnAboveLevel(ft, 75);

            Series st = atm.calculateST(hi, lo, cl);

            Series stUp1 = atm.turnsUpBelowLevel(st, 100);
            Series stDn1 = atm.turnsDnAboveLevel(st, 0);

            Series stUp2 = st > 75;
            Series stDn2 = st < 25;

            Series sigUp3 = (stUp2).And(ftUp1);
            Series sigDn3 = (stDn2).And(ftDn1);

            Series sigUp1 = (stUp1).And(ftUp1);
            Series sigDn1 = (stDn1).And(ftDn1);
            Series STFT = sigUp1 - sigDn1;
            return STFT;
        }

