        private static Series calculateFTorPAlertUp(Series[] bars)
        {
            Series op = bars[0];
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            Dictionary<string, Series> signals = new Dictionary<string, Series>();

            signals["Pressure Alert Up"] = atm.calculatePressureAlert(op, hi, lo, cl);
            Series PrsSig = signals["Pressure Alert Up"];

            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftUp = atm.turnsUpBelowLevel(ft, 100);


            Series PorFTTurnsUp = (PrsSig).Or(ftUp);

            return PorFTTurnsUp;
        }

