        private static Series calculateBullishMWOWithin(int level, Series[] bars)
        {
            ElliottWaveOutput output = calculateElliottWave(bars);
            int wave = (int)(output.wave[0][output.wave[0].Count - 1]);

            int barCount = bars[3].Count;
            Series result = new Series(barCount, 0);

            if (wave == 3 || wave == 4)
            {
                Series mid = (bars[1] + bars[2]) / 2;
                Series mwo = mid.osc(OscType.Difference, MAType.Simple, MAType.Simple, 5, 35);
                int count = mwo.Count;
                int state = 0;
                double peak = 0;
                for (int ii = count - 1; ii >= 0 && state < 2; ii--)
                {
                    if (state == 0 && mwo[ii] > 0)
                    {
                        state = 1;
                    }
                    else if (state == 1 && mwo[ii] < 0)
                    {
                        state = 2;
                    }
                    peak = Math.Max(peak, mwo[ii]);
                }
                double osc0 = mwo[count - 1];
                double limit = peak * (level / 100.0);
                if (osc0 < limit && osc0 > -limit)
                {
                    result[barCount - 1] = 1;
                }
            }
            return result;
        }

        private static Series calculateBearishMWOWithin(int level, Series[] bars)
        {
            ElliottWaveOutput output = calculateElliottWave(bars);
            int wave = (int)(output.wave[0][output.wave[0].Count - 1]);

            int barCount = bars[3].Count;
            Series result = new Series(barCount, 0);

            if (wave == -3 || wave == -4)
            {
                Series mid = (bars[1] + bars[2]) / 2;
                Series mwo = mid.osc(OscType.Difference, MAType.Simple, MAType.Simple, 5, 35);
                int count = mwo.Count;
                int state = 0;
                double valley = 0;
                for (int ii = count - 1; ii >= 0 && state < 2; ii--)
                {
                    if (state == 0 && mwo[ii] < 0)
                    {
                        state = 1;
                    }
                    else if (state == 1 && mwo[ii] > 0)
                    {
                        state = 2;
                    }
                    valley = Math.Min(valley, mwo[ii]);
                }
                double osc0 = mwo[count - 1];
                double limit = valley * (level / 100.0);
                if (osc0 > limit && osc0 < -limit)
                {
                    result[barCount - 1] = 1;
                }
            }
            return result;
        }

