        private static Series calculateSigmaSignalUp(double percent, Series[] bars)
        {
            Series ok1 = calculateSigmaSignal(1, percent, bars);
            Series ok2 = calculateSigmaSignal(2, percent, bars);
            Series ok3 = calculateSigmaSignal(3, percent, bars);
            return ok1.Or(ok2.Or(ok3));
        }
        private static Series calculateSigmaSignalDown(double percent, Series[] bars)
        {
            Series ok1 = calculateSigmaSignal(-1, percent, bars);
            Series ok2 = calculateSigmaSignal(-2, percent, bars);
            Series ok3 = calculateSigmaSignal(-3, percent, bars);
            return ok1.Or(ok2.Or(ok3));
        }

        private static Series calculateSigmaSignal(int level, double percent, Series[] bars) // level 1, 2, or 3 above -1, -2, -3 below
        {
            int barCount = bars[3].Count;
            Series result = new Series(barCount, 0);
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];
            List<Series> ts = atm.calculate3Sigma(hi, lo, cl);
            for (int ii = 0; ii < barCount; ii++)
            {
                double sigma = ((level > 0) ? ts[3 - level] : ts[-level + 2])[ii];
                double close = cl[ii];
                if (!double.IsNaN(sigma) && !double.IsNaN(close))
                {
                    double upper = ((1.0 + percent / 100.0) * sigma);
                    double lower = ((1.0 - percent / 100.0) * sigma);
                    if (close > lower && close < upper)
                    {
                        result[ii] = 1;
                    }
                }
            }
            return result;
        }

        private static Series calculateTargetSignal(int level, int percent, Series[] bars) // level 1, 2, 3, 4, or above -1, -2, -3, -4, -5 below
        {
            int barCount = bars[3].Count;
            Series result = new Series(barCount, 0);
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            Series md = Series.Mid(hi, lo);
            Dictionary<string, Series> tl = atm.calculateTrend(hi, lo, cl, md);
            Series TLup = tl["TLup"];
            Series TLdn = tl["TLdn"];

            List<Series> ul = atm.calculateUpperTargetLines(hi, lo, TLup, barCount - 1);
            List<Series> ll = atm.calculateLowerTargetLines(hi, lo, TLdn, barCount - 1);

            for (int ii = 0; ii < barCount; ii++)
            {
                double target = ((level > 0) ? ul[level - 1] : ll[-level - 1])[ii];
                double close = cl[ii];
                if (!double.IsNaN(target) && !double.IsNaN(close))
                {
                    double upper = ((1.0 + percent / 100.0) * target);
                    double lower = ((1.0 - percent / 100.0) * target);
                    if (close > lower && close < upper)
                    {
                        result[ii] = 1;
                    }
                }
            }
            return result;
        }

        private static Series calculatepercentPriceProjectionSignal(int number, int percent, Series[] bars)
        {
            ElliottWaveOutput output = calculateElliottWave(bars);
            Series waves = output.projectionWaveNumber;
            Series prices = output.projectionPrice;

            int barCount = bars[3].Count;
            double c0 = bars[3][barCount - 1];
            double c1 = bars[3][barCount - 2];

            int wave = (int)(output.wave[0][output.wave[0].Count - 1]); 

            Series result = new Series(barCount, 0);

            int count = waves.Count;
            for (int ii = 0; ii < count; ii++)
            {
                if (waves[ii] == Math.Abs(number))
                {
                    double price = prices[ii];
                    if (number > 0 && number == wave && c0 > ((1.0 - percent / 100.0) * price))
                    {
                        result[barCount - 1] = 1;
                        break;
                    }
                    else if (number < 0 && wave == number && c0 < ((1.0 + percent / 100.0) * price))
                    {
                        result[barCount - 1] = 1;
                        break;
                    }
                }
            }
            return result;
        }

