            Series mid = (hi + lo) / 2;

            Series ma = Series.EMAvg(mid, 34);
            Series TBUp = lo > ma;

            return TBUp;
        }

        private static Series calculateFirstBullishTB(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];

            Series mid = (hi + lo) / 2;

            Series ma = Series.EMAvg(mid, 34);

            Series TBUp = lo > ma;
            Series TBDn = hi < ma;

            Series upSet = (TBUp);
            Series dnSet = (TBDn);

            Series TBUpBar = atm.setReset(upSet, dnSet);   

            Series TBFirstUp = Series.Equal(TBUpBar - (TBUpBar >> 1), 1);

            return TBFirstUp;
        }

        private static Series calculateFirstBearishTB(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];

            Series mid = (hi + lo) / 2;

            Series ma = Series.EMAvg(mid, 34);

            Series TBUp = lo > ma;
            Series TBDn = hi < ma;

            Series upSet = (TBUp);
            Series dnSet = (TBDn);

            Series TBDnBar = atm.setReset(dnSet, upSet);

            Series TBFirstDn = Series.Equal(TBDnBar - (TBDnBar >> 1), 1);

            return TBFirstDn;
        }

        private static Series calculateBearishTB(Series[] bars)
        {
