        private static Series calculateLWBUp(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];

            Series mid = (hi + lo) / 2;

            Series ma = Series.EMAvg(mid, 34);
            Series TBUp = lo > ma;
            Series TBDn = hi < ma;

            Series TBFlat = (lo <= ma).And(hi >= ma);
            Series range = hi - lo;
            Series LWBUp1 = TBFlat.And(TBUp << 1).And(range > ((range << 1) * 2));

            return LWBUp1;
        }

        private static Series calculateLWBDn(Series[] bars)
        {
            Series hi = bars[1];
            Series lo = bars[2];

            Series mid = (hi + lo) / 2;

            Series ma = Series.EMAvg(mid, 34);
            Series TBUp = lo > ma;
            Series TBDn = hi < ma;

            Series TBFlat = (lo <= ma).And(hi >= ma);
            Series range = hi - lo;
            Series LWBDn1 = TBFlat.And(TBDn << 1).And(range > ((range << 1) * 2));

            return LWBDn1;
        }

