        private static Series calculateFTup2BarsDn(Series[] bars)
        {
            Series op = bars[0];
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftGoingUp = atm.goingUp(ft);

            Series twobarsdown = op.ShiftRight(1) > op & cl.ShiftRight(1) > cl & op > cl.ShiftRight(1);
            Series ftup2barsdown = ft.ShiftRight(1) > 25 & ft > 25 & ft.ShiftRight(1) < 75 & ft < 75 & ftGoingUp.ShiftRight(1) & ftGoingUp & twobarsdown;

            return ftup2barsdown;
        }

        private static Series calculateFTdn2BarsUp(Series[] bars)
        {
            Series op = bars[0];
            Series hi = bars[1];
            Series lo = bars[2];
            Series cl = bars[3];

            Series ft = atm.calculateFT(hi, lo, cl);
            Series ftGoingDn = atm.goingDn(ft);

            Series twobarsup = op.ShiftRight(1) < op & cl.ShiftRight(1) < cl & op < cl.ShiftRight(1);
            Series ftdn2barsup = ft.ShiftRight(1) > 25 & ft > 25 & ft.ShiftRight(1) < 75 & ft < 75 & ftGoingDn.ShiftRight(1) & ftGoingDn & twobarsup;

            return ftdn2barsup;
        }

