        private static Series calculateTradeCondition(bool bullish, bool trend, bool exit, string symbol, string interval, List<DateTime> times)
        {
            int barCount = times.Count;
            Series result = new Series(barCount, 0);
            List<Trade> positions = Trade.Manager.getPositions(symbol, getDatabaseInterval(interval));
            positions.Sort();

            int previousDirection = 0;
            int positionCount = positions.Count;
            int positionIndex = 0;
            double value = 0;
            DateTime date = (positionIndex < positionCount) ? positions[0].OpenDateTime : DateTime.MaxValue;
            for (int ii = 0; ii < barCount; ii++)
            {
                if (times[ii] >= date)
                {
                    int direction = (int)positions[positionIndex].Direction;
                    bool ok1 = (!exit && direction == 1 && bullish && trend);
                    bool ok2 = (!exit && direction == -1 && !bullish && trend);
                    bool ok3 = (!exit && direction == 3 && bullish && !trend);
                    bool ok4 = (!exit && direction == -3 && !bullish && !trend);
                    bool ok5 = (exit && direction == 0 && previousDirection == 1 && bullish);
                    bool ok6 = (exit && direction == 0 && previousDirection == -1 && !bullish);
                    value = (ok1 || ok2 || ok3 || ok4 || ok5 || ok6) ? 1 : 0;
                    positionIndex++;
                    previousDirection = direction;
                    date = (positionIndex < positionCount) ? positions[0].OpenDateTime : DateTime.MaxValue;
                }
                result[ii] = value;
            }
            return result;
        }

        private static string getDatabaseInterval(string input)
        {
            string interval = "";
            if (input == "Daily") interval = "D";
            else if (input == "Weekly") interval = "W";
            else if (input == "Monthly") interval = "M";
            else if (input == "Quarterly") interval = "Q";
            else if (input == "SemiAnnually") interval = "S";
            else if (input == "Yearly") interval = "Y";
            else interval = input.Replace(" MIN", "");
            return interval;
        }

        public static List<string> GetAllFundamentalFields()
        {
            var output = new List<string>();

            output.AddRange(getFundamentalFields());
            return output;
        }

        public static List<string> getFundamentalFields(string name = "Main")
        {
            var output = new List<string>();
            var conditions = GetConditionList(name);

            if (conditions.Length == 0 && name != "Fields")
            {
                output.Add(name);
            }
            else if (name != "ATM")
            {
                foreach (var condition in conditions)
                {
                    output.AddRange(getFundamentalFields(condition));
                }
            }
            return output;
        }

        public static List<string> GetAllFundamentalFactors(string name)
        {
            var output = new List<string>();

            output.AddRange(getFundamentalFactors(name));
            output.Sort();
            return output;
        }

        public static List<string> getFundamentalFactors(string name = "Main")
        {
            var output = new List<string>();
            var conditions = GetFactorList(name);

            if (conditions.Length == 0 && name != "Fields")
            {
                string[] fields = name.Split(':');
                name = (fields.Length > 1) ? fields[1] : fields[0];
                output.Add(name);
            }
            else if (name.Length >= 3 && name.Substring(0, 3) != "ATM")
            {
                foreach (var condition in conditions)
                {
                    output.AddRange(getFundamentalFactors(condition));
                }
            }
            else
            {
				foreach (var condition in conditions)
				{
					output.AddRange(getFundamentalFactors(condition));
				}
			}
            return output;
        }

