            {
                if (!currentOnly.Contains(field))
                {
                    outputList.Add(field);
                }
            }
            return outputList.ToArray();
        }


        static Dictionary<string, string[]> _conditions = new Dictionary<string, string[]>();

        public static string[] GetConditionList(string name = "Main")
        {
            lock (_conditions)
            {
                if (!_conditions.ContainsKey(name))
                {
                    initConditions(name);
                }
                string[] output = { };
                string[] value = null;
                if (_conditions.TryGetValue(name, out value))
                {
                    output = value;
                }
                return output;
            }
        }

        public static string GetFieldNameFromDescription(string description)
        { 
            string output = description.Replace("\u0002", "");
            string fieldName;
            if (_fundamentalFields.TryGetValue(description, out fieldName))
            {
                output = fieldName;
            }
            return output;
        }

        private static Dictionary<string, string> _fundamentalFields = new Dictionary<string, string>();

        private static void initConditions(string name)
        {
            var names = getConditionList(name);
            if (names.Length > 0)
            {
                _conditions[name] = names;
                foreach (var item in names)
                {
                    initConditions(item);
                }
            }
            else
            {
                string[] fields = name.Split(':');
                if (fields.Length >= 2)
                {
                    _fundamentalFields[fields[0]] = fields[1];
                }
            }
        }

        private static string[] getConditionList(string name = "Main")
        {
            string[] conditions = { };

            if (name == "Main")  // used in Scans
            {
                conditions = new string[] {

                    "POPULAR FUNDAMENTAL CHOICES",
                    //"POPULAR FILTERS",
                    "ATM CONDITION",
                    "ATM STUDY OUTPUT",
                    //"ATM RESEARCH OUTPUT",
                    "COMPANY ESTIMATES",
                    "COMPANY FUNDAMENTALS",
                    "ENVIRONMENTAL SOCIAL GOVERNANCE",
                    "FUNDAMENTAL RATIOS",
                    "INDUSTRY FACTORS",
                    "OWNERSHIP",
                    "STYLE FACTORS",
                    "CORRELATION",
                    "COEFFICIENT OF DETERMINATION",
                    "VOLATILITY",
                    "INDEX FUNDAMENTALS"
                };
            }
            else if (name == "ATMDataServer")  // used in Factor Inputs
            {
                conditions = new string[] {

                    "ATM CONDITION"
                };
            }
            else if (name == "ATMStrategies")
            {
                return Model.ATMStrategies;
            }
            else if (name == "ATMMLTrainerData")  // used in Factor Inputs
            {
                if (BarServer.ConnectedToCQG() && !BarServer.ConnectedToBloomberg())
                {
                    // just CQG
                    conditions = new string[] {
                        //"ATM DEFAULTS", //ok CQG
                        "ATM CONDITIONS", //ok CQG
                         //"ATM CURRENT RESEARCH", //of CQG todo
                        //ATM STUDY OUTPUT", //ok CQG
                        //"NORMALIZED BARS", //ok CQG
                        //"PRICE COMPARISONS", //ok CQG
                        //"PRICE PATTERNS", //ok CQG
                        //"STANDARD TECHNICALS", //ok CQG
                        //"USER FEATURE DATA"
